"use server";

import { createClient } from "@/lib/supabase/server";
import { ActionResponse } from "@/types/index";
import { revalidatePath } from "next/cache";
import { logActivity } from "@/lib/audit";
import { createNotification } from "@/lib/notifications";

export type PaymentRecord = {
    id: string;
    amount: number;
    status: string;
    payment_method: string;
    plan: string | null;
    created_at: string;
    tournament_id: string | null;
    provider_id: string | null;
    subscription_expires_at: string | null;
};

export async function getPaymentHistory(): Promise<PaymentRecord[]> {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) return [];

    const { data, error } = await supabase
        .from("payments")
        .select("*")
        .eq("user_id", user.id)
        .order("created_at", { ascending: false });

    if (error) {
        console.error("Error fetching payment history:", error);
        return [];
    }

    return data as PaymentRecord[];
}

export async function recordPayment(data: {
    tournament_id?: string;
    amount: number;
    status: string;
    payment_method: string;
    charge_id?: string;
    plan_type?: string;
}): Promise<ActionResponse> {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) return { success: false, error: "User not authenticated" };

    const insertData: any = {
        user_id: user.id,
        amount: data.amount,
        status: data.status,
        payment_method: data.payment_method,
        provider_id: data.charge_id,
        plan: data.plan_type,
        tournament_id: data.tournament_id
    };

    // Calculate expiration if paying for a subscription
    const isSubscription = data.plan_type === 'monthly' || data.plan_type === 'yearly';
    if (isSubscription && data.status === 'success') {
        const now = new Date();
        const expiresAt = new Date(now);

        if (data.plan_type === 'monthly') {
            expiresAt.setMonth(expiresAt.getMonth() + 1);
        } else if (data.plan_type === 'yearly') {
            expiresAt.setFullYear(expiresAt.getFullYear() + 1);
        }

        if (!insertData.subscription_expires_at) {
            insertData.subscription_expires_at = expiresAt.toISOString();
        }
    }

    const { error } = await supabase.from("payments").insert(insertData);

    if (error) {
        console.error("Error recording payment:", error);
        return { success: false, error: error.message };
    }

    // Revalidate multiple paths to ensure UI updates
    revalidatePath("/organizer/billing");
    revalidatePath("/manager/billing");
    revalidatePath("/dashboard/billing");
    revalidatePath("/organizer/dashboard");
    revalidatePath("/manager/dashboard");
    revalidatePath("/");

    // Log and Notify
    await logActivity('PAYMENT_RECORDED', 'payment', data.charge_id || 'manual', { amount: data.amount, status: data.status });
    if (data.status === 'success') {
        await createNotification(user.id, 'payment', 'Payment Successful', `Your payment of α╕┐${data.amount} was successful.`);
    }

    return { success: true };
}

export async function updateProfilePaymentStatus(_data: {
    payment_status: string;
    payment_id?: string;
    payment_method?: string;
    plan?: string;
}): Promise<ActionResponse> {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) return { success: false, error: "User not authenticated" };

    return { success: true };
}

"use server";

import { ActionResponse } from "@/types/index";
import { createClient } from "@/lib/supabase/server";

export async function verifySlip(formData: FormData): Promise<ActionResponse<{ amount: number, referenceNo: string, publicUrl: string }>> {
    try {
        const file = formData.get("slip") as File;
        if (!file) {
            return { success: false, error: "No slip file provided" };
        }

        if (file.size > 5 * 1024 * 1024) {
            return { success: false, error: "File size must be less than 5MB" };
        }

        if (!file.type.startsWith("image/")) {
            return { success: false, error: "File must be an image" };
        }

        const supabase = await createClient();

        // Get current user for path organization
        const { data: { user }, error: authError } = await supabase.auth.getUser();
        if (authError || !user) {
            return { success: false, error: "Unauthorized" };
        }

        const referenceNo = `SLIP-${Date.now()}-${Math.floor(Math.random() * 1000)}`;
        const fileExt = file.name.split('.').pop() || 'jpg';
        const fileName = `billing/${user.id}/${referenceNo}.${fileExt}`;

        const { error: uploadError } = await supabase.storage
            .from('slips')
            .upload(fileName, file);

        if (uploadError) {
            console.error("Upload error:", uploadError);
            return { success: false, error: "Failed to upload slip image" };
        }

        const { data: urlData } = supabase.storage
            .from('slips')
            .getPublicUrl(fileName);

        return {
            success: true,
            data: {
                amount: 0, // Admin will verify the amount
                referenceNo: referenceNo,
                publicUrl: urlData.publicUrl
            }
        };

    } catch (error: any) {
        console.error("Slip verification error:", error);
        return {
            success: false,
            error: error?.message || "Failed to verify slip"
        };
    }
}

"use server"

import { createClient } from "@/lib/supabase/server"
import { ActionResponse } from "@/types"
import { requireAdminAuth } from "@/lib/admin-auth"

export async function submitBugReport(message: string): Promise<ActionResponse<null>> {
    try {
        const supabase = await createClient()

        // Get current user if available
        const { data: userData } = await supabase.auth.getUser()
        const user = userData?.user

        const { error } = await supabase
            .from("bug_reports")
            .insert({
                user_id: user?.id || null,
                user_email: user?.email || null,
                message: message,
                status: 'unread'
            })

        if (error) {
            console.error("Error submitting bug report:", error)
            return {
                success: false,
                error: "Failed to submit report. Please try again later."
            }
        }

        return {
            success: true,
            message: "Report submitted successfully. Thank you for your feedback!"
        }
    } catch (e: any) {
        console.error("Unexpected error submitting bug report:", e)
        return {
            success: false,
            error: "An unexpected error occurred."
        }
    }
}

export async function getBugReports(): Promise<ActionResponse<any[]>> {
    const auth = await requireAdminAuth();
    if (!auth.authorized) return { success: false, error: auth.error };

    try {
        const supabase = auth.supabase;

        const { data, error } = await supabase
            .from("bug_reports")
            .select("*")
            .order("created_at", { ascending: false })
            .limit(5000)

        if (error) {
            console.error("Error fetching bug reports:", error)
            return {
                success: false,
                error: "Failed to load reports."
            }
        }

        return {
            success: true,
            data: data || []
        }
    } catch (e: any) {
        console.error("Unexpected error fetching bug reports:", e)
        return {
            success: false,
            error: "An unexpected error occurred."
        }
    }
}

export async function markBugReportAsRead(id: string): Promise<ActionResponse<null>> {
    const auth = await requireAdminAuth();
    if (!auth.authorized) return { success: false, error: auth.error };

    try {
        const supabase = auth.supabase;

        const { error } = await supabase
            .from("bug_reports")
            .update({ status: 'read' })
            .eq("id", id)

        if (error) {
            console.error("Error marking bug report as read:", error)
            return {
                success: false,
                error: "Failed to update report status."
            }
        }

        return {
            success: true
        }
    } catch (e: any) {
        console.error("Unexpected error updating bug report:", e)
        return {
            success: false,
            error: "An unexpected error occurred."
        }
    }
}

export async function resolveBugReport(id: string): Promise<ActionResponse<null>> {
    const auth = await requireAdminAuth();
    if (!auth.authorized) return { success: false, error: auth.error };

    try {
        const supabase = auth.supabase;

        const { error } = await supabase
            .from("bug_reports")
            .update({ status: 'resolved' })
            .eq("id", id)

        if (error) {
            console.error("Error resolving bug report:", error)
            return {
                success: false,
                error: "Failed to resolve report."
            }
        }

        return {
            success: true
        }
    } catch (e: any) {
        console.error("Unexpected error resolving bug report:", e)
        return {
            success: false,
            error: "An unexpected error occurred."
        }
    }
}

