export async function updateTeamPayment(
    tournamentId: string,
    teamId: string,
    status: 'pending' | 'paid' | 'waived',
    amount?: number,
    notes?: string
): Promise<ActionResponse> {
    const access = await validateTournamentAccess(tournamentId, 'editor');
    if (!access.success) return { success: false, error: access.error };

    const supabase = await createClient();

    const { error } = await supabase
        .from("team_payments")
        .upsert({
            tournament_id: tournamentId,
            team_id: teamId,
            status,
            amount: amount ?? 0,
            notes: notes || null,
            paid_at: status === 'paid' ? new Date().toISOString() : null,
        }, {
            onConflict: 'tournament_id,team_id'
        });

    if (error) {
        return { success: false, error: error.message };
    }

    revalidatePath(`/organizer/tournaments/${tournamentId}`);
    return { success: true };
}

export async function getFinancialSummary(tournamentId: string): Promise<ActionResponse<{
    totalTeams: number;
    paidTeams: number;
    pendingTeams: number;
    waivedTeams: number;
    totalExpected: number;
    totalReceived: number;
}>> {
    const access = await validateTournamentAccess(tournamentId, 'viewer');
    if (!access.success) return { success: false, error: access.error };

    const supabase = await createClient();

    const { data, error } = await supabase
        .from("team_payments")
        .select("*")
        .eq("tournament_id", tournamentId);

    if (error) {
        return { success: false, error: error.message };
    }

    const payments = data || [];
    const summary = {
        totalTeams: payments.length,
        paidTeams: payments.filter(p => p.status === 'paid').length,
        pendingTeams: payments.filter(p => p.status === 'pending').length,
        waivedTeams: payments.filter(p => p.status === 'waived').length,
        totalExpected: payments.reduce((sum, p) => sum + (Number(p.amount) || 0), 0),
        totalReceived: payments.filter(p => p.status === 'paid').reduce((sum, p) => sum + (Number(p.amount) || 0), 0),
    };

    return { success: true, data: summary };
}

"use server";

import { createClient } from "@/lib/supabase/server";
import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import { ActionResponse, Match } from "@/types/index";
import { logActivity } from "@/lib/audit";
import { initTournamentStructure } from "@/lib/fixture-utils";
import { validateTournamentAccess } from "@/lib/security";
import { deleteFileFromUrl } from "@/lib/supabase/storage";
import { validateUploadedFile } from "@/lib/file-validation";

export async function addTeam(
    tournamentId: string,
    prevState: any,
    formData: FormData
): Promise<ActionResponse> {
    const supabase = await createClient();
    const name = formData.get("name") as string;
    const sport = (formData.get("sport") as string) || 'football';
    const description = formData.get("description") as string;
    const logoFile = formData.get("logo") as File;
    const logoUrlInput = formData.get("logo_url") as string;

    if (!name) {
        return { success: false, error: "Team name is required" };
    }

    // Security Check: Ensure user is authorized
    const access = await validateTournamentAccess(tournamentId, 'editor');
    if (!access.success) return { success: false, error: access.error };
    const user = access.user;

    // Check global plan
    const { data: globalSubscription } = await supabase
        .from("payments")
        .select("id")
        .eq("user_id", user.id)
        .eq("status", "success")
        .in("plan", ["monthly", "yearly"])
        .is("tournament_id", null)
        .limit(1)
        .single();

    const _isPro = !!globalSubscription;

    // Check Team Limit
    const { data: tourney } = await supabase
        .from("tournaments")
        .select("max_teams")
        .eq("id", tournamentId)
        .single();

    const { count } = await supabase
        .from("tournament_teams")
        .select("*", { count: 'exact', head: true })
        .eq("tournament_id", tournamentId);

    const limit = tourney?.max_teams || 8;
    if (count !== null && count >= limit) {
        return { success: false, error: `Team limit reached (Max ${limit} teams).` };
    }

    let logo_url = logoUrlInput || null;

    // Handle File Upload if URL is not provided
    if (!logo_url && logoFile && logoFile.size > 0) {
        const fileCheck = validateUploadedFile(logoFile);
        if (!fileCheck.valid) return { success: false, error: fileCheck.error };

        const fileExt = logoFile.name.split('.').pop();
        const fileName = `${Date.now()}.${fileExt}`;
        const filePath = `${tournamentId}/${fileName}`;

        const { error: uploadError } = await supabase.storage
            .from('team-logos')
            .upload(filePath, logoFile);

        if (uploadError) {
            console.error("Logo upload failed", uploadError);
            return { success: false, error: `Logo upload failed: ${uploadError.message}` };
        } else {
            const { data: { publicUrl } } = supabase.storage
                .from('team-logos')
                .getPublicUrl(filePath);
            logo_url = publicUrl;
        }
    }

    const { data: teamData, error } = await supabase.from("tournament_teams").insert({
        tournament_id: tournamentId,
        team_id: null,
        name,
        sport,
        description: description || null,
        logo_url,
        created_at: new Date().toISOString(),
    }).select().single();

    if (error) {
        return { success: false, error: error.message };
    }

    // Sync with team_payments for Financial Summary
    if (teamData) {
        // Fetch tournament fee
        const { data: tournament } = await supabase
            .from("tournaments")
            .select("registration_fee")
            .eq("id", tournamentId)
            .single();

        await supabase
            .from("team_payments")
            .upsert({
                tournament_id: tournamentId,
                team_id: teamData.id,
                amount: Number(tournament?.registration_fee || 0),
                status: 'waived',
                paid_at: new Date().toISOString(),
                notes: `Added manually by admin`,
            }, {
                onConflict: 'tournament_id,team_id'
            });
    }

    revalidatePath(`/organizer/tournaments/${tournamentId}`);
    await logActivity('ADD_TEAM', 'tournament', tournamentId, { team_name: name });
    return { success: true };
}

