export function BugReportList({ initialReports }: { initialReports: any[] }) {
    const t = useTranslations("Admin")
    const [reports, setReports] = useState(initialReports)
    const [searchTerm, setSearchTerm] = useState("")
    const [selectedReport, setSelectedReport] = useState<any | null>(null)
    const [dialogOpen, setDialogOpen] = useState(false)
    const [page, setPage] = useState(1);
    const itemsPerPage = 100;

    const filteredReports = reports.filter(r =>
        (r.message?.toLowerCase() || "").includes(searchTerm.toLowerCase()) ||
        (r.user_email?.toLowerCase() || "").includes(searchTerm.toLowerCase())
    );

    const paginatedReports = filteredReports.slice((page - 1) * itemsPerPage, page * itemsPerPage);
    const totalPages = Math.ceil(filteredReports.length / itemsPerPage) || 1;

    const handleMarkAsRead = async (id: string) => {
        const res = await markBugReportAsRead(id)
        if (res.success) {
            setReports(prev =>
                prev.map(r => r.id === id ? { ...r, status: 'read' } : r)
            )
            toast.success(t("report_marked_read_success"))
        } else {
            toast.error(t("update_status_failed"))
        }
    }

    const handleViewReport = async (report: any) => {
        setSelectedReport(report)
        setDialogOpen(true)

        if (report.status === 'unread') {
            const res = await markBugReportAsRead(report.id)
            if (res.success) {
                setReports(prev =>
                    prev.map(r => r.id === report.id ? { ...r, status: 'read' } : r)
                )
            } else {
                toast.error(t("update_status_failed"))
            }
        }
    }

    const handleResolve = async (id: string) => {
        const res = await resolveBugReport(id)
        if (res.success) {
            setReports(prev =>
                prev.map(r => r.id === id ? { ...r, status: 'resolved' } : r)
            )
            setDialogOpen(false)
            toast.success(t("report_resolved_success"))
        } else {
            toast.error(t("update_status_failed"))
        }
    }

    const getStatusBadge = (status: string) => {
        if (status === 'unread') {
            return <Badge variant="destructive" className="rounded-none text-[10px] font-black uppercase">{t("report_status_new")}</Badge>
        }
        if (status === 'read') {
            return <Badge variant="secondary" className="rounded-none text-[10px] font-black uppercase">{t("report_status_read")}</Badge>
        }
        return <Badge variant="outline" className="rounded-none text-[10px] font-black uppercase">{t("report_status_resolved")}</Badge>
    }

    return (
        <div className="space-y-4">
            <div className="relative w-full md:w-[300px]">
                <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                <Input
                    placeholder={t("search_reports")}
                    className="pl-8"
                    value={searchTerm}
                    onChange={(e) => {
                        setSearchTerm(e.target.value);
                        setPage(1);
                    }}
                />
            </div>

            <div className="rounded-none border border-border bg-card overflow-hidden">
                <Table>
                    <TableHeader>
                        <TableRow className="border-b border-border bg-muted/30 hover:bg-muted/30">
                            <TableHead className="w-[100px] text-[10px] font-black uppercase italic tracking-[0.15em] text-muted-foreground">{t("status")}</TableHead>
                            <TableHead className="text-[10px] font-black uppercase italic tracking-[0.15em] text-muted-foreground">{t("report_date")}</TableHead>
                            <TableHead className="text-[10px] font-black uppercase italic tracking-[0.15em] text-muted-foreground">{t("reporter")}</TableHead>
                            <TableHead className="text-[10px] font-black uppercase italic tracking-[0.15em] text-muted-foreground">{t("report_message")}</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {reports.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={4} className="h-24 text-center text-muted-foreground">
                                    {t("no_reports")}
                                </TableCell>
                            </TableRow>
                        ) : (
                            paginatedReports.map((report) => (
                                <TableRow
                                    key={report.id}
                                    className={`cursor-pointer transition-colors hover:bg-muted/10 border-b border-border/50 ${report.status === 'unread' ? 'bg-destructive/5' : ''}`}
                                    onClick={() => handleViewReport(report)}
                                >
                                    <TableCell>
                                        {getStatusBadge(report.status)}
                                    </TableCell>
                                    <TableCell className="text-xs text-muted-foreground whitespace-nowrap">
                                        {format(new Date(report.created_at), "dd MMM yyyy HH:mm", { locale: th })}
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex items-center gap-2">
                                            <div className="h-6 w-6 bg-secondary/10 flex items-center justify-center border border-secondary/20 shrink-0">
                                                <User className="h-3 w-3 text-secondary" />
                                            </div>
                                            <span className="text-sm truncate max-w-[150px]">
                                                {report.user_email || t("anonymous")}
                                            </span>
                                        </div>
                                    </TableCell>
                                    <TableCell className="max-w-md">
                                        <span className="text-sm truncate block">{report.message}</span>
                                    </TableCell>
                                </TableRow>
                            ))
                        )}
                    </TableBody>
                </Table>
            </div>

            {filteredReports.length > 0 && (
                <div className="flex items-center justify-between py-2">
                    <div className="text-[10px] uppercase tracking-wider font-bold text-muted-foreground hidden sm:block">
                        Showing {(page - 1) * itemsPerPage + 1} to {Math.min(page * itemsPerPage, filteredReports.length)} of {filteredReports.length} entries
                    </div>
                    <div className="flex items-center space-x-2">
                        <Button
                            variant="outline"
                            size="sm"
                            className="rounded-none text-[10px] font-black uppercase"
                            onClick={() => setPage(p => Math.max(1, p - 1))}
                            disabled={page === 1}
                        >
                            Previous
                        </Button>
                        <span className="text-[10px] uppercase tracking-wider font-bold text-muted-foreground px-2">Page {page} of {totalPages}</span>
                        <Button
                            variant="outline"
                            size="sm"
                            className="rounded-none text-[10px] font-black uppercase"
                            onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                            disabled={page === totalPages}
                        >
                            Next
                        </Button>
                    </div>
                </div>
            )}

            <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
                <DialogContent className="sm:max-w-[525px] rounded-none border-border p-0 overflow-hidden">
                    <div className="bg-secondary/10 px-6 py-5 border-b border-border relative">
                        <div className="absolute top-0 left-0 w-1 h-full bg-secondary" />
                        <DialogHeader>
                            <DialogTitle className="text-xl font-black italic uppercase tracking-tighter text-foreground flex items-center gap-2">
                                <AlertCircle className="h-5 w-5 text-secondary" />
                                {t("report_details")}
                            </DialogTitle>
                            <DialogDescription className="text-muted-foreground text-sm font-medium pt-1">
                                {t("reported_at")}: {selectedReport ? format(new Date(selectedReport.created_at), "dd MMMM yyyy HH:mm", { locale: th }) : ''}
                                <br />
                                {t("reporter")}: {selectedReport?.user_email || t("anonymous")}
                            </DialogDescription>
                        </DialogHeader>
                    </div>

                    <div className="px-6 py-6">
                        <div className="p-4 bg-muted/30 border border-border whitespace-pre-wrap leading-relaxed text-sm">
                            {selectedReport?.message}
                        </div>

                        <div className="flex justify-end gap-2 mt-6">
                            <Button
                                variant="outline"
                                onClick={() => setDialogOpen(false)}
                                className="rounded-none text-[10px] font-black uppercase"
                            >
                                {t("close")}
                            </Button>
                            {selectedReport && selectedReport.status === 'unread' && (
                                <Button
                                    variant="secondary"
                                    onClick={() => handleMarkAsRead(selectedReport.id)}
                                    className="rounded-none text-[10px] font-black uppercase"
                                >
                                    {t("mark_as_read")}
                                </Button>
                            )}
                            {selectedReport && selectedReport.status !== 'resolved' && (
                                <Button
                                    onClick={() => handleResolve(selectedReport.id)}
                                    className="rounded-none text-[10px] font-black uppercase"
                                >
                                    {t("mark_as_resolved")}
                                </Button>
                            )}
                        </div>
                    </div>
                </DialogContent>
            </Dialog>
        </div>
    )
}

"use server";

import { createClient } from "@/lib/supabase/server";
import { logActivity } from "@/lib/audit";
import { ActionResponse } from "@/types";

export async function logAuthEvent(action: 'LOGIN' | 'REGISTER', userId: string, details: any = {}) {
    await logActivity(action, 'user', userId, details);
}

export async function serverSideLogin(email: string): Promise<ActionResponse> {
    // This is just for logging - the actual auth still happens on client or we can migrate it
    // For now, let's create a server action that can be called after successful client-side login
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (user) {
        await logActivity('LOGIN', 'user', user.id, { email });
        return { success: true };
    }
    return { success: false, error: "Not logged in" };
}

export async function serverSideSignup(userId: string, email: string): Promise<ActionResponse> {
    await logActivity('REGISTER', 'user', userId, { email });
    return { success: true };
}

"use server";

import { createClient } from "@/lib/supabase/server";
import { ActionResponse } from "@/types/index";
import { revalidatePath } from "next/cache";
import { logActivity } from "@/lib/audit";
import { createNotification } from "@/lib/notifications";

export type PaymentRecord = {
    id: string;
    amount: number;
    status: string;
    payment_method: string;
    plan: string | null;
    created_at: string;
    tournament_id: string | null;
    provider_id: string | null;
    subscription_expires_at: string | null;
};

export async function getPaymentHistory(): Promise<PaymentRecord[]> {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) return [];

    const { data, error } = await supabase
        .from("payments")
        .select("*")
        .eq("user_id", user.id)
        .order("created_at", { ascending: false });

    if (error) {
        console.error("Error fetching payment history:", error);
        return [];
    }

    return data as PaymentRecord[];
}

export async function recordPayment(data: {
    tournament_id?: string;
    amount: number;
    status: string;
    payment_method: string;
    charge_id?: string;
    plan_type?: string;
}): Promise<ActionResponse> {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) return { success: false, error: "User not authenticated" };

    const insertData: any = {
        user_id: user.id,
        amount: data.amount,
        status: data.status,
        payment_method: data.payment_method,
        provider_id: data.charge_id,
        plan: data.plan_type,
        tournament_id: data.tournament_id
    };

    // Calculate expiration if paying for a subscription
    if ((data.plan_type === 'monthly' || data.plan_type === 'yearly') && data.status === 'success') {
        const now = new Date();
        const expiresAt = new Date(now);

        if (data.plan_type === 'monthly') {
            expiresAt.setMonth(expiresAt.getMonth() + 1);
        } else if (data.plan_type === 'yearly') {
            expiresAt.setFullYear(expiresAt.getFullYear() + 1);
        }

        // Only set if not already set (e.g. by a provider or previous logic)
        if (!insertData.subscription_expires_at) {
            insertData.subscription_expires_at = expiresAt.toISOString();
        }
    }

    const { error } = await supabase.from("payments").insert(insertData);

    if (error) {
        console.error("Error recording payment:", error);
        return { success: false, error: error.message };
    }

    revalidatePath("/dashboard/billing");
    revalidatePath("/dashboard");
    revalidatePath("/");

    // Log and Notify
    await logActivity('PAYMENT_RECORDED', 'payment', data.charge_id || 'manual', { amount: data.amount, status: data.status });
    if (data.status === 'success') {
        await createNotification(user.id, 'payment', 'Payment Successful', `Your payment of α╕┐${data.amount} was successful.`);
    }

    return { success: true };
}

export async function updateProfilePaymentStatus(_data: {
    payment_status: string;
    payment_id?: string;
    payment_method?: string;
    plan?: string;
}): Promise<ActionResponse> {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) return { success: false, error: "User not authenticated" };

    // The pro status is derived from the 'payments' table history, 
    // so we don't need to duplicate this data in the 'profiles' table 
    // which may not even have these columns.
    return { success: true };
}

"use server";

import { ActionResponse } from "@/types/index";
import { createClient } from "@/lib/supabase/server";

export async function verifySlip(formData: FormData): Promise<ActionResponse<{ amount: number, referenceNo: string, publicUrl: string }>> {
    try {
        const file = formData.get("slip") as File;
        if (!file) {
            return { success: false, error: "No slip file provided" };
        }

        if (file.size > 5 * 1024 * 1024) {
            return { success: false, error: "File size must be less than 5MB" };
        }

        if (!file.type.startsWith("image/")) {
            return { success: false, error: "File must be an image" };
        }

        const supabase = await createClient();

        // Get current user for path organization
        const { data: { user }, error: authError } = await supabase.auth.getUser();
        if (authError || !user) {
            return { success: false, error: "Unauthorized" };
        }

        const referenceNo = `SLIP-${Date.now()}-${Math.floor(Math.random() * 1000)}`;
        const fileExt = file.name.split('.').pop() || 'jpg';
        const fileName = `billing/${user.id}/${referenceNo}.${fileExt}`;

        const { error: uploadError } = await supabase.storage
            .from('slips')
            .upload(fileName, file);

        if (uploadError) {
            console.error("Upload error:", uploadError);
            return { success: false, error: "Failed to upload slip image" };
        }

        const { data: urlData } = supabase.storage
            .from('slips')
            .getPublicUrl(fileName);

        return {
            success: true,
            data: {
                amount: 0, // Admin will verify the amount
                referenceNo: referenceNo,
                publicUrl: urlData.publicUrl
            }
        };

    } catch (error: any) {
        console.error("Slip verification error:", error);
        return {
            success: false,
            error: error?.message || "Failed to verify slip"
        };
    }
}

