    revalidatePath(`/organizer/tournaments/${tournamentId}`);
    return { success: true };
}

// Helper to advance winner
async function advanceWinner(match: Match, winnerId: string, supabase: any) {
    if (match.match_index === null || match.match_index === undefined) return;

    // 1. Get all matches for current round to find relative position
    // We sort by match_index ASC so we get 0, 1, 2, 3... order relative to the round
    const { data: currentRoundMatches } = await supabase
        .from('matches')
        .select('id, match_index')
        .eq('tournament_id', match.tournament_id)
        .eq('round', match.round)
        .order('match_index', { ascending: true });

    if (!currentRoundMatches || currentRoundMatches.length === 0) return;

    // Find index of current match in the list
    const indexInRound = currentRoundMatches.findIndex((m: any) => m.id === match.id);
    if (indexInRound === -1) return;

    // 2. Determine target match position in next round
    const nextRound = match.round + 1;
    const nextMatchPosition = Math.floor(indexInRound / 2);
    const isHomePos = indexInRound % 2 === 0;

    // 3. Fetch next round matches to find the one at that position
    const { data: nextRoundMatches } = await supabase
        .from('matches')
        .select('*')
        .eq('tournament_id', match.tournament_id)
        .eq('round', nextRound)
        .order('match_index', { ascending: true });

    if (nextRoundMatches && nextRoundMatches[nextMatchPosition]) {
        const nextMatch = nextRoundMatches[nextMatchPosition];
        const updateData = isHomePos ? { home_team_id: winnerId } : { away_team_id: winnerId };

        await supabase.from('matches').update(updateData).eq('id', nextMatch.id);
    }
}

// Helper to calc standings
function getGroupStandings(groupTeams: any[], allMatches: any[]) {
    return groupTeams.map(t => {
        const teamMatches = allMatches.filter(m =>
            (m.home_team_id === t.id || m.away_team_id === t.id)
        );

        let points = 0;
        let gd = 0;
        let gf = 0;

        teamMatches.forEach(m => {
            if (!['finished', 'live'].includes(m.status)) return;

            const isHome = m.home_team_id === t.id;
            const myScore = isHome ? m.home_score : m.away_score;
            const otherScore = isHome ? m.away_score : m.home_score;

            if (myScore !== null && otherScore !== null) {
                if (myScore > otherScore) points += 3;
                else if (myScore === otherScore) points += 1;

                gd += (myScore - otherScore);
                gf += myScore;
            }
        });

        return { ...t, points, gd, gf };
    }).sort((a: any, b: any) => {
        if (b.points !== a.points) return b.points - a.points;

        // Head-to-Head (H2H) Points
        const h2hMatches = allMatches.filter(m =>
            (m.home_team_id === a.id && m.away_team_id === b.id) ||
            (m.home_team_id === b.id && m.away_team_id === a.id)
        );

        let aH2HPoints = 0;
        let bH2HPoints = 0;

        h2hMatches.forEach(m => {
            const aIsHome = m.home_team_id === a.id;
            const aScore = aIsHome ? m.home_score : m.away_score;
            const bScore = aIsHome ? m.away_score : m.home_score;

            if (aScore !== null && bScore !== null) {
                if (aScore > bScore) aH2HPoints += 3;
                else if (bScore > aScore) bH2HPoints += 3;
                else {
                    aH2HPoints += 1;
                    bH2HPoints += 1;
                }
            }
        });

        if (bH2HPoints !== aH2HPoints) return bH2HPoints - aH2HPoints;

        if (b.gd !== a.gd) return b.gd - a.gd;
        return b.gf - a.gf;
    });
}

"use server";

import { createClient } from "@/lib/supabase/server";
import { revalidatePath } from "next/cache";
import { ActionResponse, TournamentMember } from "@/types";
import { logActivity } from "@/lib/audit";
import { validateTournamentAccess } from "@/lib/security";

/**
 * Invite a collaborator to a tournament by email.
 * Creates a pending TournamentMember record.
 */
export async function inviteCollaborator(
    tournamentId: string,
    email: string,
    role: 'editor' | 'viewer' = 'editor'
): Promise<ActionResponse<TournamentMember>> {
    const supabase = await createClient();

    // Security Check: Only the tournament owner (Admin) can invite collaborators
    const access = await validateTournamentAccess(tournamentId, 'admin');
    if (!access.success) return { success: false, error: access.error };
    const user = access.user;

    // Check if the email is already invited
    const { data: existing } = await supabase
        .from("tournament_members")
        .select("id, status")
        .eq("tournament_id", tournamentId)
        .eq("email", email.toLowerCase())
        .single();

    if (existing) {
        return { success: false, error: "This email has already been invited" };
    }

    // Check if the email is the owner's email
    if (user.email?.toLowerCase() === email.toLowerCase()) {
        return { success: false, error: "You cannot invite yourself" };
    }

    // Create the invitation
    const { data, error } = await supabase
        .from("tournament_members")
        .insert({
            tournament_id: tournamentId,
            email: email.toLowerCase(),
            role: role,
            status: 'pending',
            user_id: null // Will be linked when they accept
        })
        .select()
        .single();

    if (error) {
        console.error("Error inviting collaborator:", error);
        return { success: false, error: error.message };
    }

    revalidatePath(`/organizer/tournaments/${tournamentId}`);
    await logActivity('INVITE_MEMBER', 'tournament', tournamentId, { email, role });
    return { success: true, data };
}

/**
 * Get all collaborators for a tournament.
 */
export async function getCollaborators(
    tournamentId: string
): Promise<ActionResponse<TournamentMember[]>> {
    // Security Check: Only collaborators or owner can see the member list
    const access = await validateTournamentAccess(tournamentId, 'viewer');
    if (!access.success) return { success: false, error: access.error };

    const supabase = await createClient();

    const { data, error } = await supabase
        .from("tournament_members")
        .select("*")
        .eq("tournament_id", tournamentId)
        .order("created_at", { ascending: true });

    if (error) {
        console.error("Error fetching collaborators:", error);
        return { success: false, error: error.message };
    }

    return { success: true, data: data || [] };
}

/**
 * Remove a collaborator from a tournament.
 */
export async function removeCollaborator(
    memberId: string,
    tournamentId: string
): Promise<ActionResponse> {
    const supabase = await createClient();

    // Security Check: Only the tournament owner (Admin) can remove collaborators
    const access = await validateTournamentAccess(tournamentId, 'admin');
    if (!access.success) return { success: false, error: access.error };

    const { error } = await supabase
        .from("tournament_members")
        .delete()
        .eq("id", memberId)
        .eq("tournament_id", tournamentId);

    if (error) {
        console.error("Error removing collaborator:", error);
        return { success: false, error: error.message };
    }

    revalidatePath(`/organizer/tournaments/${tournamentId}`);
    await logActivity('REMOVE_MEMBER', 'tournament', tournamentId, { member_id: memberId });
    return { success: true };
}

/**
 * Get the current user's role for a specific tournament.
 * Returns null if the user has no access.
 */
export async function getUserRole(
    tournamentId: string
): Promise<ActionResponse<{ role: 'admin' | 'editor' | 'viewer' | null; isOwner: boolean }>> {
    const supabase = await createClient();

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) {
        return { success: true, data: { role: null, isOwner: false } };
    }

    // Check if user is the owner
    const { data: tournament } = await supabase
        .from("tournaments")
        .select("user_id")
        .eq("id", tournamentId)
        .single();

    if (tournament && tournament.user_id === user.id) {
        return { success: true, data: { role: 'admin', isOwner: true } };
    }

    // Check if user is a collaborator (by user_id or email)
    const { data: member } = await supabase
        .from("tournament_members")
        .select("role, status")
        .eq("tournament_id", tournamentId)
        .or(`user_id.eq.${user.id},email.eq.${user.email?.toLowerCase()}`)
        .eq("status", "accepted")
        .single();

    if (member) {
        return { success: true, data: { role: member.role, isOwner: false } };
    }

    return { success: true, data: { role: null, isOwner: false } };
}

/**
 * Accept a collaboration invite.
 * Links the current user to the pending member record.
 */
export async function acceptInvite(
    tournamentId: string
): Promise<ActionResponse> {
    const supabase = await createClient();

    const { data: { user } } = await supabase.auth.getUser();
    if (!user || !user.email) {
        return { success: false, error: "Please log in to accept the invite" };
    }

    // Find pending invite for this email
    const { data: member, error: fetchError } = await supabase
        .from("tournament_members")
        .select("*")
        .eq("tournament_id", tournamentId)
        .eq("email", user.email.toLowerCase())
        .eq("status", "pending")
        .single();

    if (fetchError || !member) {
        return { success: false, error: "No pending invite found for your email" };
    }

    // Update the member record
    const { data: updated, error } = await supabase
        .from("tournament_members")
        .update({
            user_id: user.id,
            status: 'accepted'
        })
        .eq("id", member.id)
        .select()
        .single();

    if (error || !updated) {
        console.error("Error accepting invite:", error);
        return { success: false, error: error?.message || "Failed to accept invite" };
    }

    // Refresh relevant paths
    revalidatePath(`/organizer/tournaments/${tournamentId}`);
    revalidatePath(`/dashboard/invites`);
    revalidatePath(`/dashboard`);

    return { success: true };
}

/**
 * Check if the current user has a pending invite for any tournament.
 * Used on dashboard to show notifications.
 */
export async function getPendingInvites(): Promise<ActionResponse<Array<{
    id: string;
    tournament_id: string;
    tournament_name?: string;
    role: string;
}>>> {
    const supabase = await createClient();

    const { data: { user } } = await supabase.auth.getUser();
    if (!user || !user.email) {
        return { success: true, data: [] };
    }

    const { data, error } = await supabase
        .from("tournament_members")
        .select(`
            id,
            tournament_id,
            role,
            tournaments (
                name
            )
        `)
        .eq("email", user.email.toLowerCase())
        .eq("status", "pending");

    if (error) {
        console.error("Error fetching pending invites:", error);
        return { success: false, error: error.message };
    }

    const invites = (data || []).map((item: any) => ({
        id: item.id,
        tournament_id: item.tournament_id,
        tournament_name: item.tournaments?.name,
        role: item.role
    }));

    return { success: true, data: invites };
}

