    if (!access.success) return { success: false, error: access.error };

    const supabase = await createClient();

    const { data, error } = await supabase
        .from("team_payments")
        .select(`
            *,
            teams (name, logo_url)
        `)
        .eq("tournament_id", tournamentId)
