export async function getFinancialSummary(tournamentId: string): Promise<ActionResponse<{
    totalTeams: number;
    paidTeams: number;
    pendingTeams: number;
    waivedTeams: number;
    totalExpected: number;
    totalReceived: number;
}>> {
    // Security Check: Only tournament managers can view financial summary
    const access = await validateTournamentAccess(tournamentId, 'viewer');
    if (!access.success) return { success: false, error: access.error };

    const supabase = await createClient();

    const { data, error } = await supabase
        .from("team_payments")
        .select("*")
        .eq("tournament_id", tournamentId);

    if (error) {
        return { success: false, error: error.message };
    }

    const payments = data || [];
    const summary = {
        totalTeams: payments.length,
        paidTeams: payments.filter(p => p.status === 'paid').length,
        pendingTeams: payments.filter(p => p.status === 'pending').length,
        waivedTeams: payments.filter(p => p.status === 'waived').length,
        totalExpected: payments.reduce((sum, p) => sum + (Number(p.amount) || 0), 0),
        totalReceived: payments.filter(p => p.status === 'paid').reduce((sum, p) => sum + (Number(p.amount) || 0), 0),
    };

    return { success: true, data: summary };
}

"use server";

import { createClient, createAdminClient } from "@/lib/supabase/server";
import { ActionResponse, GlobalPlayer } from "@/types/index";
import { deleteFileFromUrl } from "@/lib/supabase/storage";
import { validateUploadedFile } from "@/lib/file-validation";

async function isAuthorizedForPlayer(playerId: string, userId: string) {
    const supabase = await createClient();
    
    const { data: player } = await supabase
        .from("players")
        .select("team_id, global_team_id")
        .eq("id", playerId)
        .single();
    
    if (!player) return false;

    const teamId = player.team_id || player.global_team_id;
    if (!teamId) return false;

    // Check global team ownership
    const { data: globalTeam } = await supabase
        .from("teams")
        .select("id")
        .eq("id", teamId)
        .eq("user_id", userId)
        .single();
    
    if (globalTeam) return true;

    // Check tournament team ownership/management
    const { data: participation } = await supabase
        .from("tournament_teams")
        .select("user_id, tournament_id")
        .eq("id", teamId)
        .single();
    
    if (participation) {
        if (participation.user_id === userId) return true;

        const { data: tournament } = await supabase
            .from("tournaments")
            .select("user_id")
            .eq("id", participation.tournament_id)
            .single();
        
        if (tournament && tournament.user_id === userId) return true;

        const { data: membership } = await supabase
            .from("tournament_members")
            .select("role")
            .eq("tournament_id", participation.tournament_id)
            .eq("user_id", userId)
            .eq("status", "accepted")
            .in("role", ["admin", "editor"])
            .single();
        
        if (membership) return true;
    }

    return false;
}

async function isAuthorizedForGlobalPlayer(globalPlayerId: string, userId: string) {
    const supabase = await createClient();
    
    // Check if user created this global player
    const { data: gp } = await supabase
        .from("global_players")
        .select("created_by")
        .eq("id", globalPlayerId)
        .single();
    
    if (gp && gp.created_by === userId) return true;

    // Check if user is an organizer of ANY tournament where this player is participating
    const { data: participations } = await supabase
        .from("players")
        .select("team_id, tournament_teams!inner(tournament_id)")
        .eq("global_player_id", globalPlayerId);
    
    if (participations) {
        for (const p of participations) {
            const tournamentId = (p as any).tournament_teams?.tournament_id;
            if (tournamentId) {
                // Check if user is organizer
                const { data: tournament } = await supabase
                    .from("tournaments")
                    .select("user_id")
                    .eq("id", tournamentId)
                    .single();
                
                if (tournament && tournament.user_id === userId) return true;

                const { data: membership } = await supabase
                    .from("tournament_members")
                    .select("role")
                    .eq("tournament_id", tournamentId)
                    .eq("user_id", userId)
                    .eq("status", "accepted")
                    .in("role", ["admin", "editor"])
                    .single();
                
                if (membership) return true;
            }
        }
    }

    return false;
}

export async function getGlobalPlayers(
    page: number = 1,
    pageSize: number = 10,
    search: string = ""
): Promise<ActionResponse<{ players: GlobalPlayer[]; totalCount: number }>> {
    const supabase = await createClient();
    const from = (page - 1) * pageSize;
    const to = from + pageSize - 1;

    let query = supabase
        .from("global_players")
        .select("*", { count: "exact" });

    if (search) {
        query = query.ilike("name", `%${search}%`);
    }

    const { data, error, count } = await query
        .order("name", { ascending: true })
        .range(from, to);

    if (error) {
        return { success: false, error: error.message };
    }

    return {
        success: true,
        data: {
            players: (data as GlobalPlayer[]) || [],
            totalCount: count || 0,
        },
    };
}

export async function searchGlobalPlayers(query: string): Promise<ActionResponse<GlobalPlayer[]>> {
    const supabase = await createClient();

    let dbQuery = supabase
        .from("global_players")
        .select("*");

    if (query && query.trim().length > 0) {
        dbQuery = dbQuery.ilike("name", `%${query.trim()}%`);
    }

    const { data, error } = await dbQuery
        .order("name", { ascending: true })
        .limit(20);

    if (error) {
        return { success: false, error: error.message };
    }

    return { success: true, data: data as GlobalPlayer[] };
}

export async function createGlobalPlayer(
    name: string,
    photoUrl?: string | null,
    dateOfBirth?: string | null
): Promise<ActionResponse<GlobalPlayer>> {
    const supabase = await createClient();
    const adminSupabase = createAdminClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return { success: false, error: "Authentication required" };

    const { data, error } = await adminSupabase
        .from("global_players")
        .insert({
            name,
            photo_url: photoUrl || null,
            date_of_birth: dateOfBirth || null,
            created_by: user?.id || null,
        })
        .select()
        .single();

    if (error) {
        return { success: false, error: error.message };
    }

    return { success: true, data: data as GlobalPlayer };
}

export async function linkPlayerToGlobal(
    playerId: string,
    globalPlayerId: string
): Promise<ActionResponse> {
    const supabase = await createClient();
    const adminSupabase = createAdminClient();

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return { success: false, error: "Authentication required" };

    const authorized = await isAuthorizedForPlayer(playerId, user.id);
    if (!authorized) return { success: false, error: "Unauthorized to link this player" };

    const { error } = await adminSupabase
