import { _notFound } from "next/navigation";
import { createAdminClient } from "@/lib/supabase/server";
import { MatchConsolePage } from "@/components/matches/match-console-page";
import { getUserSubscriptionPlan } from "@/actions/common/user";

export default async function AdminMatchConsole(props: {
    params: Promise<{ locale: string, id: string, matchId: string }>,
    searchParams: Promise<{ [key: string]: string | string[] | undefined }>
}) {
    const { _locale, id, matchId } = await props.params;
    const resolvedParams = await props.searchParams;
    const fromTab = typeof resolvedParams.from === 'string' ? resolvedParams.from : 'fixtures';

    const supabase = createAdminClient();

    // Fetch the match details
    const { data: match, error: matchError } = await supabase
        .from('matches')
        .select(`
            *,
            home_team:tournament_teams!matches_home_team_id_fkey(id, name, logo_url),
            away_team:tournament_teams!matches_away_team_id_fkey(id, name, logo_url)
        `)
        .eq('id', matchId)
        .eq('tournament_id', id)
        .single();

    if (matchError || !match) {
        console.error("Match fetch error:", matchError, "Match ID:", matchId);
        return <div className="p-8 text-red-500">Error fetching match: {JSON.stringify(matchError, null, 2)}</div>;
    }

    // Fetch the tournament to check if Pro plan
    const { data: tournament } = await supabase
        .from('tournaments')
        .select('plan')
        .eq('id', id)
        .single();

    // Fetch global user plan
    const userPlan = await getUserSubscriptionPlan();

    // Pro status is true if tournament has specific plan OR user has global plan
    const isPro = (tournament?.plan && tournament.plan !== 'free') || userPlan === 'monthly' || userPlan === 'yearly';

    // Fetch initial events
    const { data: events } = await supabase
        .from('match_events')
        .select(`
            id, match_id, team_id, player_id, event_type, minute, extra_info, created_at,
            player:players(name)
        `)
        .eq('match_id', matchId)
        .order('created_at', { ascending: true });

    // Transformer for events
    const formattedEvents = (events || []).map(e => ({
        ...e,
        player_name: (e.player as any)?.name || (Array.isArray(e.player) ? (e.player[0] as any)?.name : null),
        player: undefined
    }));

    return (
        <MatchConsolePage
            match={match}
            tournamentId={id}
            goals={[]}
            isPro={!!isPro}
            readOnly={false}
            initialEvents={formattedEvents as any}
            backUrl={`/organizer/tournaments/${id}?tab=${fromTab}`}
        />
    );
}

import { notFound } from "next/navigation";
import { createClient } from "@/lib/supabase/server";
import { Match, Team, Goal } from "@/types/index";
import { TournamentContent } from "./tournament-content";
import { getUserRole } from "@/actions/organizer/tournaments/collaborator";
import { getUserSubscriptionPlan } from "@/actions/common/user";

export default async function TournamentPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = await params;
    const supabase = await createClient();

    // Parallel fetching: Tournament data, User Plan, User Role
    // Note: getUserSubscriptionPlan internally fetches user, so we don't need to fetch it separately for plan logic
    // But we might need user object later? No, we just need userPlan string.

    // We can't fully parallelize everything because some queries depend on dynamic data?
    // No, everything depends on `id` or current user.
    // Let's refactor into Promise.all for cleaner async flow.

    const [tournamentResult, userPlan, roleRes] = await Promise.all([
        supabase.from("tournaments").select(`
            id, name, format, description, status, start_date, end_date, number_of_pitches, user_id, created_at, sport,
            max_teams, advancing_teams, is_registration_open, registration_fee, bank_name, bank_account_name, bank_account_number,
            document_deadline,
            payments(plan, status)
        `).eq("id", id).single(),
        getUserSubscriptionPlan(),
        getUserRole(id)
    ]);

    const tournament = tournamentResult.data ? {
        ...tournamentResult.data,
        plan: (tournamentResult.data as any).payments?.some((p: any) => p.status === 'success' && (p.plan === 'tournament' || p.plan === 'per_tournament')) ? 'tournament' : 'free'
    } : null;
    const tournamentError = tournamentResult.error;

    if (tournamentError || !tournament) {
        notFound();
    }

    // Fetch related data (Teams, Matches, Goals) parallelized
    const [teamsResult, matchesResult] = await Promise.all([
        supabase.from("tournament_teams").select("*, team:teams(user_id)").eq("tournament_id", id).order("created_at", { ascending: true }),
        supabase.from("matches").select(`
            *,
            home_team:tournament_teams!matches_home_team_id_fkey(name, logo_url),
            away_team:tournament_teams!matches_away_team_id_fkey(name, logo_url)
        `).eq("tournament_id", id)
            .order("round", { ascending: true })
            .order("match_index", { ascending: true })
            .order("created_at", { ascending: true })
    ]);

    const teams = teamsResult.data || [];
    const matches = matchesResult.data || [];

    // Fetch goals for Top Scorers (only if matches exist)
    let tournamentGoals: any[] = [];
    if (matches && matches.length > 0) {
        const matchIds = matches.map(m => m.id);
        const { data: goalsData } = await supabase
            .from("goals")
            .select("*")
            .in("match_id", matchIds);
        tournamentGoals = goalsData || [];
    }

    const userRole = roleRes.success && roleRes.data ? roleRes.data.role : null;
    const isOwner = roleRes.success && roleRes.data ? roleRes.data.isOwner : false;

    // Calculate Pro Status
    const isGlobalPro = userPlan === 'monthly' || userPlan === 'yearly';
    const isTournamentPro = (tournament as any).payments?.some((p: any) => p.status === 'success' && (p.plan === 'tournament' || p.plan === 'per_tournament'));
    const isSharedWithMe = !isOwner && userRole !== null;

    const isPro = !!(isGlobalPro || isTournamentPro || isSharedWithMe);

    return (
        <TournamentContent
            tournament={tournament}
            initialMatches={matches as Match[] || []}
            initialTeams={teams as Team[] || []}
            initialGoals={tournamentGoals as Goal[]}
            userPlan={userPlan}
            initialIsPro={isPro}
            id={id}
            userRole={userRole}
        />
    );
}

"use server";

import { createClient } from "@/lib/supabase/server";
import { revalidatePath } from "next/cache";
import { ActionResponse, PenaltyShot, _Match } from "@/types/index";

async function syncPenaltyScore(matchId: string) {
    const supabase = await createClient();

    // 1. Get the match to know home/away teams
    const { data: matchData, error: matchError } = await supabase
        .from("matches")
        .select("id, home_team_id, away_team_id, tournament_id")
        .eq("id", matchId)
        .single();

    if (matchError || !matchData) return;

    // 2. Get all successful shots for this match
    const { data: shotsData, error: shotsError } = await supabase
        .from("penalty_shootouts")
        .select("team_id, scored")
        .eq("match_id", matchId)
        .eq("scored", true);

    if (shotsError) return;

    // 3. Count
    const homeScore = shotsData.filter(s => s.team_id === matchData.home_team_id).length;
    const awayScore = shotsData.filter(s => s.team_id === matchData.away_team_id).length;

    // 4. Update match
    await supabase
        .from("matches")
        .update({
            penalty_home_score: homeScore,
            penalty_away_score: awayScore
        })
        .eq("id", matchId);

    revalidatePath(`/organizer/tournaments/${matchData.tournament_id}`);
}

export async function getPenaltyShootout(matchId: string): Promise<ActionResponse<PenaltyShot[]>> {
    const supabase = await createClient();

    const { data, error } = await supabase
        .from("penalty_shootouts")
        .select(`
            *,
            players (name)
        `)
        .eq("match_id", matchId)
        .order("round")
        .order("created_at");

    if (error) {
        return { success: false, error: error.message };
    }

    const shots = (data || []).map((shot: any) => ({
        ...shot,
        player: shot.players ? { name: shot.players.name } : null,
    }));

    return { success: true, data: shots as PenaltyShot[] };
}

export async function addPenaltyShot(
    matchId: string,
    teamId: string,
    round: number,
    scored: boolean,
    playerId?: string | null
): Promise<ActionResponse> {
    const supabase = await createClient();

    const { error } = await supabase
        .from("penalty_shootouts")
        .insert({
            match_id: matchId,
            team_id: teamId,
            player_id: playerId || null,
            round,
            scored,
        });

    if (error) {
        return { success: false, error: error.message };
    }

    await syncPenaltyScore(matchId);

    return { success: true };
}

export async function deletePenaltyShot(shotId: string): Promise<ActionResponse> {
    const supabase = await createClient();

    // Need matchId to sync
    const { data: shotData } = await supabase
        .from("penalty_shootouts")
        .select("match_id")
        .eq("id", shotId)
        .single();

    const { error } = await supabase
        .from("penalty_shootouts")
        .delete()
        .eq("id", shotId);

    if (error) {
        return { success: false, error: error.message };
    }

    if (shotData?.match_id) {
        await syncPenaltyScore(shotData.match_id);
    }

    return { success: true };
}

export async function clearPenaltyShootout(matchId: string): Promise<ActionResponse> {
    const supabase = await createClient();

    const { error } = await supabase
        .from("penalty_shootouts")
        .delete()
        .eq("match_id", matchId);

    if (error) {
        return { success: false, error: error.message };
    }

    await syncPenaltyScore(matchId);

    return { success: true };
}

"use server";

import { createClient, createAdminClient } from "@/lib/supabase/server";
import { revalidatePath } from "next/cache";
import { ActionResponse, Player } from "@/types/index";
import { _deleteFileFromUrl } from "@/lib/supabase/storage";

async function isAuthorizedOrganizer(tournamentId: string, userId: string) {
    const supabase = await createClient();

    // Check if user is the owner of the tournament
    const { data: tournament } = await supabase
        .from("tournaments")
        .select("user_id")
        .eq("id", tournamentId)
        .single();

    if (tournament && tournament.user_id === userId) return true;

    // Check if user is a member with admin/editor role
    const { data: membership } = await supabase
        .from("tournament_members")
        .select("role")
        .eq("tournament_id", tournamentId)
        .eq("user_id", userId)
        .eq("status", "accepted")
        .in("role", ["admin", "editor"])
        .single();

    if (membership) return true;

    return false;
}

export async function addPlayer(
    teamId: string,
    prevState: any,
    formData: FormData
): Promise<ActionResponse> {
    const supabase = await createClient();
    const adminSupabase = createAdminClient();

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return { success: false, error: "Authentication required" };

    // Fetch tournament_id to check authorization
    const { data: teamData } = await supabase
        .from("tournament_teams")
        .select("tournament_id")
        .eq("id", teamId)
        .single();

    if (!teamData) return { success: false, error: "Team not found" };

    const authorized = await isAuthorizedOrganizer(teamData.tournament_id, user.id);
    if (!authorized) return { success: false, error: "Unauthorized to manage this roster" };

    const name = formData.get("name") as string;
    const number = formData.get("number") as string;
    const position = formData.get("position") as string;
    const birthDate = formData.get("birthDate") as string;

    if (!name) {
        return { success: false, error: "Player name is required" };
    }

    // Check if this is a global team or a tournament participation (Use Admin to avoid RLS)
    const { data: globalTeam } = await adminSupabase.from("teams").select("id").eq("id", teamId).single();
    const { data: participation } = await adminSupabase.from("tournament_teams").select("id").eq("id", teamId).single();

    if (!globalTeam && !participation) {
        console.error(`[addPlayer] Team ID ${teamId} not found in any team table`);
        return { success: false, error: "Invalid team context. Team record not found." };
    }

    const { error } = await adminSupabase.from("players").insert({
        team_id: participation ? teamId : null,
        global_team_id: globalTeam ? teamId : null,
        name,
        number: number ? parseInt(number) : null,
        position: position || null,
        birth_date: birthDate || null,
        photo_url: null,
        created_at: new Date().toISOString(),
    });

    if (error) {
        console.error("[addPlayer] Error inserting player:", error);
        return { success: false, error: "Failed to add player: " + error.message };
    }

    revalidatePath(`/organizer/tournaments/${teamData.tournament_id}`);
    return { success: true };
}

export async function getPlayers(teamId: string): Promise<{ success: boolean; data?: Player[]; error?: string }> {
    const supabase = await createClient();

    const { data, error } = await supabase
        .from("players")
        .select("*")
        .or(`team_id.eq.${teamId},global_team_id.eq.${teamId}`)
        .order("number", { ascending: true });

    if (error) {
        console.error("Error fetching players:", error);
        return { success: false, error: "Failed to fetch players" };
    }

    return { success: true, data: data as Player[] };
}

export async function deletePlayer(playerId: string): Promise<ActionResponse> {
    const supabase = await createClient();
    const adminSupabase = createAdminClient();

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return { success: false, error: "Authentication required" };

    const { data: player } = await supabase.from('players').select('team_id, global_team_id').eq('id', playerId).single();
    if (!player) return { success: false, error: "Player not found" };

    const effectiveTeamId = player.team_id || player.global_team_id;
    if (!effectiveTeamId) return { success: false, error: "Player team context not found" };

    // Fetch tournament_id to check authorization
    let tournamentId = null;

    if (player.team_id) {
        const { data: teamData } = await supabase
            .from("tournament_teams")
            .select("tournament_id")
            .eq("id", player.team_id)
            .single();
        tournamentId = teamData?.tournament_id;
    }

    if (!tournamentId) return { success: false, error: "Tournament context not found" };

    const authorized = await isAuthorizedOrganizer(tournamentId, user.id);
    if (!authorized) return { success: false, error: "Unauthorized to manage this roster" };

    const { error } = await adminSupabase
        .from("players")
        .delete()
        .eq("id", playerId);

    if (error) {
        return { success: false, error: error.message };
    }

    revalidatePath(`/organizer/tournaments/${tournamentId}`);
    return { success: true };
}

export async function updatePlayer(
    playerId: string,
    data: { name?: string; number?: number | null; position?: string | null; birth_date?: string | null; photo_url?: string | null }
): Promise<ActionResponse> {
    const supabase = await createClient();
    const adminSupabase = createAdminClient();

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return { success: false, error: "Authentication required" };

    const { data: player } = await supabase.from('players').select('team_id, global_team_id').eq('id', playerId).single();
    if (!player) return { success: false, error: "Player not found" };

    const effectiveTeamId = player.team_id || player.global_team_id;
    if (!effectiveTeamId) return { success: false, error: "Player team context not found" };

    // Fetch tournament_id to check authorization
    let tournamentId = null;

    if (player.team_id) {
        const { data: teamData } = await supabase
            .from("tournament_teams")
            .select("tournament_id")
            .eq("id", player.team_id)
            .single();
        tournamentId = teamData?.tournament_id;
    }

    if (!tournamentId) return { success: false, error: "Tournament context not found" };

    const authorized = await isAuthorizedOrganizer(tournamentId, user.id);
    if (!authorized) return { success: false, error: "Unauthorized to manage this roster" };

    const { error } = await adminSupabase
        .from("players")
        .update(data)
        .eq("id", playerId);

    if (error) {
        return { success: false, error: error.message };
    }

    revalidatePath(`/organizer/tournaments/${tournamentId}`);
    return { success: true };
}

