                    </div>
                    <div className="flex items-center space-x-2">
                        <Button
                            variant="outline"
                            size="sm"
                            className="rounded-none text-[10px] font-black uppercase"
                            onClick={() => setPage(p => Math.max(1, p - 1))}
                            disabled={page === 1}
                        >
                            Previous
                        </Button>
                        <span className="text-[10px] uppercase tracking-wider font-bold text-muted-foreground px-2">Page {page} of {totalPages}</span>
                        <Button
                            variant="outline"
                            size="sm"
                            className="rounded-none text-[10px] font-black uppercase"
                            onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                            disabled={page === totalPages}
                        >
                            Next
                        </Button>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { useState } from "react";
import { useTranslations } from "next-intl";
import { formatDate } from "@/lib/date";
import { useLocale } from "next-intl";
import { Search, Shield, User, MoreHorizontal, Check } from "lucide-react";
import { updateUserRole } from "@/app/[locale]/admin/actions";
import { toast } from "sonner";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuLabel,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

interface AdminUsersTableProps {
    initialUsers: any[];
}

export function AdminUsersTable({ initialUsers }: AdminUsersTableProps) {
    const t = useTranslations("Admin");
    const _tCommon = useTranslations("Common");
    const locale = useLocale();
    const [searchTerm, setSearchTerm] = useState("");
    const [page, setPage] = useState(1);
    const itemsPerPage = 100;
    const [users, setUsers] = useState(initialUsers);

    const filteredUsers = users.filter(user =>
        (user.email?.toLowerCase() || "").includes(searchTerm.toLowerCase()) ||
        (user.full_name?.toLowerCase() || "").includes(searchTerm.toLowerCase())
    );

    const paginatedUsers = filteredUsers.slice((page - 1) * itemsPerPage, page * itemsPerPage);
    const totalPages = Math.ceil(filteredUsers.length / itemsPerPage) || 1;

    const handleRoleChange = async (userId: string, newRole: string) => {
        const result = await updateUserRole(userId, newRole);
        if (result.success) {
            toast.success(t("role_updated"));
            setUsers(users.map(u => u.id === userId ? { ...u, role: newRole } : u));
        } else {
            toast.error(t("role_update_failed"));
        }
    };

    return (
        <div className="space-y-4">
            <div className="relative w-full md:w-[300px]">
                <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                <Input
                    placeholder={t("search_users")}
                    className="pl-8"
                    value={searchTerm}
                    onChange={(e) => {
                        setSearchTerm(e.target.value);
                        setPage(1);
                    }}
                />
            </div>

            <div className="rounded-none border border-border bg-card overflow-hidden">
                <Table>
                    <TableHeader>
                        <TableRow className="border-b border-border bg-muted/30 hover:bg-muted/30">
                            <TableHead className="text-[10px] font-black uppercase italic tracking-[0.15em] text-muted-foreground">{t("user")}</TableHead>
                            <TableHead className="text-[10px] font-black uppercase italic tracking-[0.15em] text-muted-foreground">{t("role")}</TableHead>
                            <TableHead className="text-[10px] font-black uppercase italic tracking-[0.15em] text-muted-foreground">{t("created_at")}</TableHead>
                            <TableHead className="text-right text-[10px] font-black uppercase italic tracking-[0.15em] text-muted-foreground">{t("actions")}</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {filteredUsers.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={4} className="h-24 text-center text-muted-foreground">
                                    {t("no_results")}
                                </TableCell>
                            </TableRow>
                        ) : (
                            paginatedUsers.map((user) => (
                                <TableRow key={user.id} className="border-b border-border/50 hover:bg-muted/10 transition-colors">
                                    <TableCell>
                                        <div className="flex items-center gap-3">
                                            <div className="h-8 w-8 bg-secondary/10 flex items-center justify-center border border-secondary/20 shrink-0">
                                                <User className="h-4 w-4 text-secondary" />
                                            </div>
                                            <div className="flex flex-col min-w-0">
                                                <span className="font-bold text-sm truncate">{user.email}</span>
                                                <span className="text-[10px] text-muted-foreground uppercase tracking-wider font-medium">{user.full_name || t("no_name")}</span>
                                            </div>
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <Badge
                                            variant={user.role === 'admin' ? 'default' : 'outline'}
                                            className="rounded-none text-[10px] font-black uppercase"
                                        >
                                            {user.role === 'admin' && <Shield className="mr-1 h-3 w-3" />}
                                            {user.role}
                                        </Badge>
                                    </TableCell>
                                    <TableCell className="text-xs text-muted-foreground">
                                        {user.created_at
                                            ? formatDate(user.created_at, "d MMM yyyy", locale)
                                            : "-"}
                                    </TableCell>
                                    <TableCell className="text-right">
                                        <DropdownMenu>
                                            <DropdownMenuTrigger asChild>
                                                <Button variant="ghost" className="h-8 w-8 p-0 hover:bg-muted/30">
                                                    <span className="sr-only">{t("actions")}</span>
                                                    <MoreHorizontal className="h-4 w-4" />
                                                </Button>
                                            </DropdownMenuTrigger>
                                            <DropdownMenuContent align="end" className="rounded-none border-border">
                                                <DropdownMenuLabel className="text-[10px] font-black uppercase tracking-wider">{t("actions")}</DropdownMenuLabel>
                                                <DropdownMenuItem onClick={() => navigator.clipboard.writeText(user.id)}>
                                                    {t("copy_user_id")}
                                                </DropdownMenuItem>
                                                <DropdownMenuSeparator />
                                                <DropdownMenuLabel className="text-[10px] font-black uppercase tracking-wider">{t("change_role")}</DropdownMenuLabel>
                                                <DropdownMenuItem onClick={() => handleRoleChange(user.id, 'user')}>
                                                    <User className="mr-2 h-4 w-4" />
                                                    {t("set_as_user")}
                                                    {user.role === 'user' && <Check className="ml-auto h-4 w-4 text-secondary" />}
                                                </DropdownMenuItem>
                                                <DropdownMenuItem onClick={() => handleRoleChange(user.id, 'admin')}>
                                                    <Shield className="mr-2 h-4 w-4" />
                                                    {t("set_as_admin")}
                                                    {user.role === 'admin' && <Check className="ml-auto h-4 w-4 text-secondary" />}
                                                </DropdownMenuItem>
                                            </DropdownMenuContent>
                                        </DropdownMenu>
                                    </TableCell>
                                </TableRow>
                            ))
                        )}
                    </TableBody>
                </Table>
            </div>
            {filteredUsers.length > 0 && (
                <div className="flex items-center justify-between py-2">
                    <div className="text-[10px] uppercase tracking-wider font-bold text-muted-foreground hidden sm:block">
                        Showing {(page - 1) * itemsPerPage + 1} to {Math.min(page * itemsPerPage, filteredUsers.length)} of {filteredUsers.length} entries
                    </div>
                    <div className="flex items-center space-x-2">
                        <Button
                            id="pagination-prev"
                            variant="outline"
                            size="sm"
                            className="rounded-none text-[10px] font-black uppercase"
                            onClick={() => {
                                setPage(p => Math.max(1, p - 1));
                                window.scrollTo({ top: 0, behavior: 'smooth' });
                            }}
                            disabled={page === 1}
                        >
                            Previous
                        </Button>
                        <span className="text-[10px] uppercase tracking-wider font-bold text-muted-foreground px-2" id="pagination-info">
                            Page {page} of {totalPages}
                        </span>
                        <Button
                            id="pagination-next"
                            variant="outline"
                            size="sm"
                            className="rounded-none text-[10px] font-black uppercase"
                            onClick={() => {
                                setPage(p => Math.min(totalPages, p + 1));
                                window.scrollTo({ top: 0, behavior: 'smooth' });
                            }}
                            disabled={page === totalPages}
                        >
                            Next
                        </Button>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { Plan } from "@/types";
import { useTranslations } from "next-intl";
import { Button } from "@/components/ui/button";
import { Check, Loader2, _RefreshCw, X, UploadCloud, _CreditCard, Smartphone, Trophy, Copy } from "lucide-react";
import { useState, useEffect, _useCallback, useRef } from "react";
import generatePayload from "promptpay-qr";
import { QRCodeSVG } from "qrcode.react";
import { recordPayment, _updateProfilePaymentStatus } from "@/actions/common/billing/general";
import { useToast } from "@/hooks/use-toast";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { _confirmPayment } from "@/actions/organizer/tournaments/general";
import { Input } from "@/components/ui/input";
import { verifySlip } from "@/actions/common/billing/slip";

interface PaymentSectionProps {
    plan: Plan;
    tournaments?: { id: string; name: string; status: string; }[] | null;
    onCancel: () => void;
    onSuccess: () => void;
    externalSelectedTournament?: string;
}

export function PaymentSection({ plan, tournaments, onCancel, onSuccess, externalSelectedTournament }: PaymentSectionProps) {
    const t = useTranslations("Billing");
    const tCommon = useTranslations("Common");
    const { toast } = useToast();

    const [selectedTournament, setSelectedTournament] = useState<string>("");
    const [isGeneratingQR, setIsGeneratingQR] = useState(false);
    const [isUploadingSlip, setIsUploadingSlip] = useState(false);
    const [paymentState, setPaymentState] = useState<{
        qrCode: string | null;
        status: 'pending' | 'success' | 'failed';
    }>({ qrCode: null, status: 'pending' });
    const [copied, setCopied] = useState(false);

    const promptPayId = process.env.NEXT_PUBLIC_PROMPTPAY_ID || "0800000000";
    const accountName = process.env.NEXT_PUBLIC_PROMPTPAY_NAME || "LeagueFlow";

    // Derive legacy plan type for backend compatibility
    const getPlanType = (): 'tournament' | 'monthly' | 'yearly' => {
        const duration = plan.duration?.toLowerCase();
        const name = plan.name?.toLowerCase();
        if (duration?.includes('tournament') || name?.includes('tournament') || duration === 'lifetime') return 'tournament';
        if (duration?.includes('year') || name?.includes('yearly')) return 'yearly';
        return 'monthly';
    };

    const planType = getPlanType();
    const eligibleTournaments = tournaments || [];
    const getPrice = () => plan.discounted_price || plan.price;
    const isGeneratingRef = useRef(false);

    const handleGenerateQR = async () => {
        const activeTournament = externalSelectedTournament || selectedTournament;
        if (planType === 'tournament' && !activeTournament) {
            toast({ title: tCommon("error"), description: t("select_tournament_hint"), variant: "destructive" });
            return;
        }

        if (isGeneratingRef.current) return;
        isGeneratingRef.current = true;
        setIsGeneratingQR(true);

        try {
            const amount = getPrice();
            const payload = generatePayload(promptPayId, { amount });

            setPaymentState({
                qrCode: payload,
                status: 'pending'
            });

        } catch (_error) {
            toast({ title: tCommon("error"), description: tCommon("something_went_wrong"), variant: "destructive" });
        } finally {
            setIsGeneratingQR(false);
            isGeneratingRef.current = false;
        }
    };

    const handleUploadSlip = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setIsUploadingSlip(true);
        try {
            const formData = new FormData();
            formData.append("slip", file);

            const res = await verifySlip(formData);
            if (res.success && res.data) {
                const referenceNo = res.data.referenceNo;
                const activeTournament = externalSelectedTournament || selectedTournament;
                const publicUrl = res.data.publicUrl;
                const chargeIdPayload = JSON.stringify({ ref: referenceNo, url: publicUrl });

                await recordPayment({
                    amount: getPrice(),
                    status: 'pending',
                    payment_method: 'promptpay',
                    charge_id: chargeIdPayload,
                    plan_type: planType,
                    tournament_id: planType === 'tournament' ? activeTournament : undefined
                });

                setPaymentState(prev => ({ ...prev, status: 'success' }));
                toast({ title: tCommon("success"), description: t("payment_pending_verification", { defaultValue: "Slip uploaded successfully. Awaiting admin verification." }) });

                setTimeout(() => {
                    onSuccess();
                }, 2000);

            } else {
                toast({ title: tCommon("error"), description: res.error || "Invalid slip", variant: "destructive" });
            }
        } catch (error) {
            toast({
                title: tCommon("error"),
                description: (error as any).message || tCommon("something_went_wrong"),
                variant: "destructive"
            });
        } finally {
            setIsUploadingSlip(false);
            e.target.value = '';
        }
    };

    const hasAutoGeneratedRef = useRef(false);

    useEffect(() => {
        hasAutoGeneratedRef.current = false;
        setPaymentState({ qrCode: null, status: 'pending' });
    }, [plan.id, plan.price]);

    useEffect(() => {
        const activeTournament = externalSelectedTournament || selectedTournament;
        const canGenerate = planType !== 'tournament' || !!activeTournament;

        if (
            canGenerate &&
            !paymentState.qrCode &&
            !isGeneratingQR &&
            !hasAutoGeneratedRef.current
        ) {
            hasAutoGeneratedRef.current = true;
            handleGenerateQR();
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [planType, selectedTournament, externalSelectedTournament, paymentState.qrCode]);

    const copyToClipboard = () => {
        navigator.clipboard.writeText(promptPayId);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    return (
        <div className="bg-card border border-border/10 shadow-2xl rounded-none p-0 overflow-hidden animate-in fade-in slide-in-from-top-2 relative">
            {/* Header */}
            <div className="bg-gradient-to-r from-secondary/10 to-transparent px-6 py-5 border-b border-border/10 relative">
                <div className="absolute top-0 left-0 w-1 h-full bg-secondary" />
                <h3 className="text-base font-black italic uppercase tracking-widest text-secondary flex items-center gap-2">
                    <Smartphone className="w-5 h-5" />
                    {t("pay_with_promptpay")}
                </h3>
                <Button 
                    variant="ghost" 
                    size="icon" 
                    className="absolute right-4 top-1/2 -translate-y-1/2 h-8 w-8 hover:bg-secondary/10 hover:text-secondary rounded-none" 
                    onClick={onCancel}
                >
                    <X className="w-4 h-4" />
                </Button>
            </div>

            {/* Plan Info Bar */}
            <div className="px-6 py-3 bg-muted/30 border-b border-border/10 flex items-center justify-between">
                <div className="flex items-center gap-2 text-[10px] font-black uppercase italic tracking-wider text-muted-foreground/60">
                    <Trophy className="w-3 h-3 text-secondary" />
                    {t("plan_prefix")}
                    <span className="text-foreground">
                        {
                            plan.name?.trim() === 'Starter' ? t('free.title') :
                                (plan.name?.trim() === 'Per Tournament' || planType === 'tournament') ? t('tournament.title') :
                                    (plan.name?.trim() === 'Monthly Pro' || planType === 'monthly') ? t('monthly.title') :
                                        (plan.name?.trim() === 'Yearly Pro' || planType === 'yearly') ? t('yearly.title') :
                                            (plan.name?.trim() === 'Manager Pro') ? t('manager_pro.title') :
                                                plan.name
                        }
                    </span>
                </div>
                <div className="flex items-baseline gap-1">
                    {plan.discounted_price ? (
                        <>
                            <span className="text-[10px] text-muted-foreground/40 line-through font-bold">
                                α╕┐{plan.price}
                            </span>
                            <span className="text-xs font-black italic text-secondary">α╕┐{plan.discounted_price}</span>
                        </>
                    ) : (
                        <span className="text-xs font-black italic text-secondary">α╕┐{plan.price}</span>
                    )}
                </div>
            </div>

            <div className="p-8">
                {planType === 'tournament' && !externalSelectedTournament && (
                    <div className="mb-8 max-w-sm mx-auto">
                        <label className="text-[10px] uppercase font-black italic tracking-widest text-muted-foreground/60 mb-2 block text-center">
                            {t("select_tournament_label")}
                        </label>
                        <Select
                            value={selectedTournament}
                            onValueChange={(val) => {
                                setSelectedTournament(val);
                                setPaymentState({ qrCode: null, status: 'pending' });
                                hasAutoGeneratedRef.current = false;
                            }}
                        >
                            <SelectTrigger className="rounded-none border-x-0 border-t-0 border-b-2 focus:ring-0 px-0 h-10 bg-transparent text-center font-bold">
                                <SelectValue placeholder={t("select_tournament_placeholder")} />
                            </SelectTrigger>
                            <SelectContent className="rounded-none">
                                {eligibleTournaments.length > 0 ? (
                                    eligibleTournaments.map((tournamentItem: any) => (
                                        <SelectItem key={tournamentItem.id} value={tournamentItem.id}>{tournamentItem.name}</SelectItem>
                                    ))
                                ) : (
                                    <SelectItem value="none" disabled>{t("no_tournaments")}</SelectItem>
                                )}
                            </SelectContent>
                        </Select>
                    </div>
                )}

                <div className="flex flex-col items-center justify-center min-h-[300px]">
                    {isGeneratingQR ? (
                        <div className="text-center space-y-4">
                            <Loader2 className="w-10 h-10 animate-spin text-secondary mx-auto" />
                            <p className="text-[10px] uppercase font-black italic tracking-widest text-muted-foreground/60 animate-pulse">
                                {tCommon("loading")}
                            </p>
                        </div>
                    ) : !paymentState.qrCode ? (
                        planType !== 'tournament' ? (
                            <div className="text-center space-y-4">
                                <Button 
                                    onClick={handleGenerateQR} 
                                    className="rounded-none font-black italic uppercase italic tracking-widest px-8 shadow-[0_0_20px_rgba(var(--secondary),0.2)]"
                                    disabled={isGeneratingQR}
                                >
                                    {isGeneratingQR ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : null}
                                    {tCommon("generate_qr")}
                                </Button>
                            </div>
                        ) : (
                            <div className="text-[10px] uppercase font-black italic tracking-widest text-muted-foreground/40 text-center animate-pulse">
