import { updateMatch } from "@/app/[locale]/organizer/tournaments/[id]/actions";
import { getPenaltyShootout } from "@/app/[locale]/organizer/tournaments/[id]/penalty-actions";
import { createClient } from "@/lib/supabase/client";

import { Button } from "@/components/ui/button";
import { _Card, _CardContent, _CardHeader, _CardTitle } from "@/components/ui/card";
import { cn } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";
import {
    Timer,
    ArrowLeft,
    Target,
    _RotateCcw,
    _History,
    _Settings,
    _User,
    Undo,
    Ban,
    Activity,
    Square,
    Repeat,
    _PlusCircle,
    Flag,
    _ArrowRight,
    Trophy,
    Stethoscope,
    Shield
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";
