                addEvent(null, 'add_time', minute, null, { added_minutes: mins }, `+${mins} min`);
                setAddTimeDialogOpen(false);
            }} />
        </div>
    );
}

"use client";

import { Check, X, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Plan } from "@/types";
import { cn } from "@/lib/utils";
import { useTranslations } from "next-intl";
import { Badge } from "@/components/ui/badge";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";

interface PricingCardsProps {
    plans: Plan[];
    currentPlan?: string | null;
    activePlan?: string;
    onSelectPlan?: (planId: string) => void;
    isLoading?: boolean;
    landingPageMode?: boolean;
    tournaments?: { id: string; name: string; status: string; plan?: string | null; }[] | null;
    selectedTournamentId?: string;
    onTournamentChange?: (id: string) => void;
}

export function PricingCards({
    plans,
    currentPlan,
    activePlan,
    onSelectPlan,
    isLoading = false,
    landingPageMode = false,
    tournaments = [],
    selectedTournamentId,
    onTournamentChange
}: PricingCardsProps) {
    const t = useTranslations('Pricing');
    const tBilling = useTranslations('Billing');

    const getTranslatedValue = (key: string, value: string | undefined | null) => {
        if (!value) return "-";

        // Name Mapping
        if (key === 'name') {
            if (value === 'Starter') return t('free.title');
            if (value === 'Per Tournament') return t('tournament.title');
            if (value === 'Monthly Pro') return t('monthly.title');
            if (value === 'Yearly Pro') return t('yearly.title');
            if (value === 'Manager Pro') return t('manager_pro.title');
        }

        // Format Mapping
        if (key === 'format') {
            if (value.includes('League') && value.includes('Knockout')) return t('comparison.val_league_ko');
            if (value.includes('Group') || value === 'All') return t('comparison.val_all_group');
        }

        // Stats Mapping
        if (key === 'stats') {
            if (value === 'Basic' || value.includes('Basic')) return t('comparison.val_basic');
            if (value.includes('Pro') || value === 'Advanced') return t('comparison.val_pro_stats');
        }

        // Support Mapping
        if (key === 'support') {
            if (value === 'Standard') return t('comparison.val_standard');
            if (value.includes('Priority')) return t('comparison.val_priority');
            if (value.includes('VIP')) return t('yearly.features.support');
        }

        // Duration Mapping
        if (key === 'duration') {
            if (value === 'monthly') return t('monthly.unit').replace('/', '').trim();
            if (value === 'yearly') return t('yearly.unit').replace('/', '').trim();
            if (value === 'lifetime') return t('tournament.unit').replace('/', '').trim();
            return value;
        }

        return value;
    };

    if (!plans || plans.length === 0) {
        return <div className="text-center p-8 text-muted-foreground">{t('no_plans')}</div>;
    }

    // Sort plans by price
    const sortedPlans = [...plans].sort((a, b) => a.price - b.price);
    const isManagerPlans = plans.length > 0 && ('max_teams' in plans[0] || (plans[0] as any).target_role === 'manager');

    return (
        <div className="overflow-x-auto rounded-none border bg-background shadow-sm pt-6">
            <table className="w-full text-sm min-w-[600px] table-fixed border-separate border-spacing-0">
                <thead>
                    <tr className="bg-muted/50">
                        <th className="p-6 text-left font-semibold w-[200px] md:w-1/4 text-lg border-b">{t('features')}</th>
                        {sortedPlans.map(plan => {
                            const isRecommended = plan.recommended;
                            return (
                                <th key={plan.id} className={cn(
                                    "p-6 text-center relative border-b",
                                    isRecommended && "border-2 border-primary/20 bg-primary/5 rounded-t-lg border-b-0"
                                )}>
                                    {isRecommended && (
                                        <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-primary text-primary-foreground text-[10px] uppercase font-bold px-2 py-0.5 rounded-none shadow-sm whitespace-nowrap z-10">
                                            {t('recommended')}
                                        </div>
                                    )}
                                    <div className="flex flex-col items-center gap-2 mb-1">
                                        <div className="text-lg font-bold">{getTranslatedValue('name', plan.name)}</div>
                                        {plan.price > 0 && (
                                            <Badge variant="default" className="text-[10px] h-4 px-1.5 uppercase font-black tracking-widest bg-primary text-primary-foreground border-none">
                                                {t('pro_badge')}
                                            </Badge>
                                        )}
                                    </div>
                                    <div className="text-muted-foreground font-normal">
                                        {plan.discounted_price ? (
                                            <div className="flex flex-col items-center">
                                                <span className="line-through text-xs opacity-70">
                                                    {new Intl.NumberFormat('th-TH', { style: 'currency', currency: 'THB', minimumFractionDigits: 0 }).format(plan.price)}
                                                </span>
                                                <span className="text-primary font-bold text-xl">
                                                    {new Intl.NumberFormat('th-TH', { style: 'currency', currency: 'THB', minimumFractionDigits: 0 }).format(plan.discounted_price)}
                                                </span>
                                            </div>
                                        ) : (
                                            <span className="text-xl font-bold">
                                                {plan.price === 0 ? t('free_label') : new Intl.NumberFormat('th-TH', { style: 'currency', currency: 'THB', minimumFractionDigits: 0 }).format(plan.price)}
                                            </span>
                                        )}
                                        {plan.duration && plan.price > 0 && <span className="text-xs ml-1">/{getTranslatedValue('duration', plan.duration)}</span>}
                                    </div>
                                </th>
                            )
                        })}
                    </tr>
                </thead>
                <tbody>
                    {/* Teams Limit */}
                    <tr className="hover:bg-muted/50 transition-colors">
                        <td className="p-4 font-medium pl-6">{isManagerPlans ? t('manager_teams_limit') : t('teams_limit')}</td>
                        {sortedPlans.map(plan => (
                            <td key={`teams-${plan.id}`} className={cn(
                                "p-4 text-center text-muted-foreground",
                                plan.recommended && "border-x-2 border-primary/20 bg-primary/5"
                            )}>
                                {(plan as any).teams_limit === 0 || (plan as any).max_teams === 0 ? t('unlimited') : ((plan as any).teams_limit ?? (plan as any).max_teams)}
                            </td>
                        ))}
                    </tr>
                    {/* Access Duration */}
                    <tr className="hover:bg-muted/50 transition-colors">
                        <td className="p-4 font-medium pl-6">{t('duration_access')}</td>
                        {sortedPlans.map(plan => {
                            const isLifetime = plan.duration === 'lifetime' || plan.name === 'Per Tournament';
                            return (
                                <td key={`duration-${plan.id}`} className={cn(
                                    "p-4 text-center text-muted-foreground",
                                    plan.recommended && "border-x-2 border-primary/20 bg-primary/5",
                                    isLifetime && "text-primary font-bold"
                                )}>
                                    {isLifetime ? t('lifetime_label') : getTranslatedValue('duration', plan.duration)}
                                </td>
                            );
                        })}
                    </tr>
                    {/* Format Support */}
                    <tr className="hover:bg-muted/50 transition-colors">
                        <td className="p-4 font-medium pl-6">{isManagerPlans ? t('manager_format_support') : t('format_support')}</td>
                        {sortedPlans.map(plan => (
                            <td key={`format-${plan.id}`} className={cn(
                                "p-4 text-center capitalize text-muted-foreground",
                                plan.recommended && "border-x-2 border-primary/20 bg-primary/5"
                            )}>
                                {getTranslatedValue('format', (plan as any).format_support ?? (plan as any).max_players_per_team?.toString())}
                            </td>
                        ))}
                    </tr>

                    {/* Invite teams via link */}
                    {!isManagerPlans && (
                        <tr className="hover:bg-muted/50 transition-colors">
                            <td className="p-4 font-medium pl-6">{t('invite_via_link')}</td>
                            {sortedPlans.map(plan => (
                                <td key={`invite-${plan.id}`} className={cn(
                                    "p-4 text-center",
                                    plan.recommended && "border-x-2 border-primary/20 bg-primary/5"
                                )}>
                                    {(plan as any).invite_enabled ? (
                                        <Check className="h-6 w-5 mx-auto text-primary" aria-hidden="true" />
                                    ) : (
                                        <X className="h-6 w-5 mx-auto text-muted-foreground opacity-50" aria-hidden="true" />
                                    )}
                                </td>
                            ))}
                        </tr>
                    )}

                    {/* Open Registration */}
                    {!isManagerPlans && (
                        <tr className="hover:bg-muted/50 transition-colors">
                            <td className="p-4 font-medium pl-6">{t('open_registration')}</td>
                            {sortedPlans.map(plan => (
                                <td key={`register-${plan.id}`} className={cn(
                                    "p-4 text-center",
                                    plan.recommended && "border-x-2 border-primary/20 bg-primary/5"
                                )}>
                                    {(plan as any).register_enabled ? (
                                        <Check className="h-6 w-5 mx-auto text-primary" aria-hidden="true" />
                                    ) : (
                                        <X className="h-6 w-5 mx-auto text-muted-foreground opacity-50" aria-hidden="true" />
                                    )}
                                </td>
                            ))}
                        </tr>
                    )}

                    {/* Statistics */}
                    {!isManagerPlans && (
                        <tr className="hover:bg-muted/50 transition-colors">
                            <td className="p-4 font-medium pl-6">{t('statistics')}</td>
                            {sortedPlans.map(plan => (
                                <td key={`stats-${plan.id}`} className={cn(
                                    "p-4 text-center text-muted-foreground capitalize",
                                    plan.recommended && "border-x-2 border-primary/20 bg-primary/5"
                                )}>
                                    {getTranslatedValue('stats', (plan as any).stats_support)}
                                </td>
                            ))}
                        </tr>
                    )}

                    {/* Support Level */}
                    <tr className="hover:bg-muted/50 transition-colors">
                        <td className="p-4 font-medium pl-6">{t('support')}</td>
                        {sortedPlans.map(plan => (
                            <td key={`support-${plan.id}`} className={cn(
                                "p-4 text-center capitalize text-muted-foreground",
                                plan.recommended && "border-x-2 border-primary/20 bg-primary/5",
                            )}>
                                {getTranslatedValue('support', plan.support_level)}
                            </td>
                        ))}
                    </tr>

                    {/* Action Buttons Row */}
                    <tr className="">
                        <td className="p-4 pl-6 border-t"></td>
                        {sortedPlans.map(plan => {
                            const isSelected = currentPlan === plan.id;
                            const isFreePlan = plan.price === 0;
                            const isPaidPlan = plan.price > 0;
                            const isMonthlyPlan = plan.duration === 'monthly' && isPaidPlan && plan.name?.trim() !== 'Manager Pro';
                            const isYearlyPlan = plan.duration === 'yearly' && isPaidPlan;
                            const isTournamentPlan = plan.name?.trim() === 'Per Tournament' || plan.duration === 'lifetime' && isPaidPlan;
                            const isManagerProPlan = plan.name?.trim() === 'Manager Pro';

                            // Check if this specific tournament is already upgraded
                            let isThisTournamentUpgraded = false;
                            if (isTournamentPlan && selectedTournamentId) {
                                const selectedTour = tournaments?.find(t => t.id === selectedTournamentId);
                                isThisTournamentUpgraded = selectedTour?.plan === 'tournament';
                            }

                            // A plan is "Effectively Active" if:
                            // 1. It's the SPECIFIC global plan the user has
                            // 2. It's the Free plan and user is on 'free'
                            // 3. It's the Per Tournament plan and (SELECTED tournament is upgraded OR user has global pro)
                            const isGlobalPro = activePlan === 'monthly' || activePlan === 'yearly';
                            const isAnyManagerPro = activePlan === 'manager_pro' || isGlobalPro;

                            const isEffectivelyActive =
                                (activePlan === 'monthly' && isMonthlyPlan) ||
                                (activePlan === 'yearly' && isYearlyPlan) ||
                                (activePlan === 'free' && isFreePlan) ||
                                (isManagerProPlan && isAnyManagerPro) ||
                                (isTournamentPlan && (isThisTournamentUpgraded || isGlobalPro));

                            return (
                                <td key={`action-${plan.id}`} className={cn(
                                    "p-4 text-center pb-6 border-t",
                                    plan.recommended && "border-2 border-t-0 border-primary/20 bg-primary/5 rounded-b-lg"
                                )}>
                                    {landingPageMode ? (
                                        <Button variant="outline" className="w-full" asChild>
                                            {/* Link needs to be handled by parent or just redirect */}
                                            <div onClick={() => window.location.href = '/dashboard'}>{t('get_started')}</div>
                                        </Button>
                                    ) : (
                                        <div className="space-y-4">
                                            {isTournamentPlan && (
                                                <div className="text-left space-y-1.5">
                                                    <Select
                                                        value={selectedTournamentId}
                                                        onValueChange={onTournamentChange}
                                                    >
                                                        <SelectTrigger className="w-full bg-background">
                                                            <SelectValue placeholder={tBilling('select_tournament_placeholder', { defaultValue: "Select Tournament" })} />
                                                        </SelectTrigger>
                                                        <SelectContent>
                                                            {tournaments && tournaments.length > 0 ? (
                                                                tournaments.map((tItem) => (
                                                                    <SelectItem key={tItem.id} value={tItem.id}>
                                                                        {tItem.name}
                                                                    </SelectItem>
                                                                ))
                                                            ) : (
                                                                <SelectItem value="none" disabled>
                                                                    {tBilling('no_tournaments', { defaultValue: "No tournaments found" })}
                                                                </SelectItem>
                                                            )}
                                                        </SelectContent>
                                                    </Select>
                                                </div>
                                            )}
                                            <Button
                                                variant={isEffectivelyActive ? "outline" : (isSelected ? "default" : "secondary")}
                                                className={cn(
                                                    "w-full",
                                                    isSelected && !isEffectivelyActive && "ring-2 ring-primary ring-offset-2"
                                                )}
                                                disabled={isEffectivelyActive || isLoading || isFreePlan || (isTournamentPlan && !selectedTournamentId)}
                                                onClick={() => onSelectPlan && onSelectPlan(plan.id)}
                                            >
                                                {isLoading && isSelected && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                                                {isEffectivelyActive ? t('current_plan') : (isSelected ? t('selected') : t('choose_plan'))}
                                            </Button>
                                        </div>
                                    )}
                                </td>
                            );
                        })}
                    </tr>
                </tbody>
            </table>
        </div>
    );
}

"use client";

import { useState, useMemo } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { Team } from "@/types/index";
import { useTranslations } from "next-intl";
import { _Calendar, _MapPin, Trophy, AlertCircle, CheckCircle2, Users, ImageIcon, X, Upload, User, _Phone, FileText, Loader2, Smartphone, _CreditCard } from "lucide-react";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";

import { Button } from "@/components/ui/button";
import {
    Form,
    FormControl,
    _FormDescription,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { _Card, _CardContent, _CardHeader, _CardTitle } from "@/components/ui/card";
import { PromptPayQR } from "./promptpay-qr";
import { registerTeam } from "@/actions/manager/register-team";
import { _Tabs, _TabsContent, _TabsList, _TabsTrigger } from "@/components/ui/tabs";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Separator } from "@/components/ui/separator";

// Schema generator based on fee
const createFormSchema = (isFree: boolean, t: any) => z.object({
    teamName: z.string().min(2, t("team_name_error")),
    contactName: z.string().min(2, t("contact_name_error")),
    contactPhone: z.string().min(10, t("contact_phone_error")),
    description: z.string().optional(),
    logoFile: z.any()
        .optional()
        .refine(
            (files) => !files || files.length === 0 || files[0].size <= 5 * 1024 * 1024,
            t("logo_size_error")
        )
        .refine(
            (files) => !files || files.length === 0 || ["image/jpeg", "image/png", "image/webp"].includes(files[0].type),
            t("logo_type_error")
        ),
    slipFile: isFree
        ? z.any().optional()
        : z.any()
            .refine((files) => files?.length === 1, t("slip_required"))
            .refine(
                (files) => files?.[0]?.size <= 5 * 1024 * 1024,
                t("slip_size_error")
            )
            .refine(
                (files) => ["image/jpeg", "image/png", "image/webp"].includes(files?.[0]?.type),
                t("slip_type_error")
            ),
});

interface RegistrationFormProps {
    tournament: {
        id: string;
        name: string;
        registration_fee: number;
        bank_account_number: string;
        bank_name: string;
        bank_account_name: string;
        is_registration_open: boolean;
        status: string;
    };
    initialTeams?: Team[];
}

export function RegistrationForm({ tournament, initialTeams }: RegistrationFormProps) {
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [success, setSuccess] = useState(false);
    const [logoPreviewUrl, setLogoPreviewUrl] = useState<string | null>(null);
    const [slipPreviewUrl, setSlipPreviewUrl] = useState<string | null>(null);
    const [selectedTeamId, setSelectedTeamId] = useState<string>("");

    const t = useTranslations("Registration");
    const isFree = Number(tournament.registration_fee) <= 0;
    const formSchema = useMemo(() => createFormSchema(isFree, t), [isFree, t]);

    const form = useForm<z.infer<typeof formSchema>>({
        resolver: zodResolver(formSchema),
        defaultValues: {
            teamName: "",
            contactName: "",
            contactPhone: "",
            description: "",
        },
    });

    const handleSelectTeam = (teamId: string) => {
        setSelectedTeamId(teamId);
        if (teamId === "new") {
            form.setValue("teamName", "");
            setLogoPreviewUrl(null);
            return;
        }

        const selectedTeam = initialTeams?.find(t => t.id === teamId);
        if (selectedTeam) {
            form.setValue("teamName", selectedTeam.name);
            form.setValue("description", selectedTeam.description || "");
            setLogoPreviewUrl(selectedTeam.logo_url || null);
        }
    };

    async function onSubmit(values: z.infer<typeof formSchema>) {
        setIsSubmitting(true);
        try {
            const formData = new FormData();
            formData.append("tournamentId", tournament.id);
            formData.append("teamName", values.teamName);
            formData.append("contactName", values.contactName);
            formData.append("contactPhone", values.contactPhone);
            if (values.description) {
                formData.append("description", values.description);
            }
            if (selectedTeamId && selectedTeamId !== "new") {
                formData.append("existingTeamId", selectedTeamId);
            }
            if (values.logoFile?.[0]) {
                formData.append("logoFile", values.logoFile[0]);
            } else if (logoPreviewUrl && !logoPreviewUrl.startsWith('data:')) {
                formData.append("logoUrl", logoPreviewUrl);
            }

            if (!isFree && values.slipFile?.[0]) {
                formData.append("slipFile", values.slipFile[0]);
            }

            const result = await registerTeam(formData);

            if (result.success) {
                setSuccess(true);
                toast.success(result.message || t("reg_success_toast"));
            } else {
                toast.error(result.error || t("reg_failed_toast"));
            }
        } catch (error) {
            toast.error("An unexpected error occurred");
            console.error(error);
        } finally {
            setIsSubmitting(false);
        }
    }

    if (success) {
        return (
            <div className="flex flex-col items-center justify-center py-12 text-center">
                <div className="w-16 h-16 bg-green-100 rounded-none flex items-center justify-center mb-6">
                    <CheckCircle2 className="w-8 h-8 text-green-600" />
                </div>
                <h2 className="text-3xl font-bold text-gray-900 mb-2">{t("success_title")}</h2>
                <p className="text-muted-foreground max-w-md mb-8">
                    {t("success_desc")} {!isFree && t("success_desc_paid")}
                </p>
                <div className="flex gap-4">
                    <Button variant="outline" onClick={() => window.location.reload()}>
                        {t("register_another")}
                    </Button>
                    <Button onClick={() => window.location.href = `/manager/tournaments`}>
                        {t("go_to_dashboard")}
                    </Button>
                </div>
            </div>
        );
    }

    const isRegistrationClosed = !tournament.is_registration_open || tournament.status === 'completed';

    return (
        <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">

                {isRegistrationClosed && (
                    <div className="flex items-center gap-3 p-4 bg-destructive/10 border border-destructive/20 text-destructive rounded-none">
                        <AlertCircle className="h-5 w-5 flex-shrink-0" />
                        <div>
                            <p className="font-bold">{t("registration_closed_title")}</p>
                            <p className="text-sm opacity-90">{t("registration_closed_desc")}</p>
                        </div>
                    </div>
                )}

                {initialTeams && initialTeams.length > 0 && (
                    <div className="space-y-4 p-4 border rounded-none bg-primary/5 border-primary/10">
                        <div className="flex items-center gap-2">
                            <Trophy className="h-4 w-4 text-primary" />
                            <h4 className="text-sm font-bold uppercase tracking-wider">{t("use_existing_team") || "Use Existing Team"}</h4>
                        </div>
                        <Select value={selectedTeamId} onValueChange={handleSelectTeam}>
                            <SelectTrigger className="rounded-none bg-background">
                                <SelectValue placeholder={t("select_team_placeholder") || "Select one of your teams..."} />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="new">{t("create_new_team") || "Create New Team"}</SelectItem>
                                {initialTeams.map((team) => (
                                    <SelectItem key={team.id} value={team.id}>
                                        {team.name}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>
                )}

                <div className="grid gap-6 md:grid-cols-2">
                    <FormField
                        control={form.control}
                        name="teamName"
                        render={({ field }) => (
                            <FormItem className="w-full md:col-span-2">
                                <FormLabel className="flex items-center gap-2">
                                    <Users className="w-4 h-4 text-muted-foreground" />
                                    {t("team_name_label")}
                                </FormLabel>
                                <FormControl>
                                    <Input placeholder={t("team_name_placeholder")} {...field} className="h-11" />
                                </FormControl>
                                <FormMessage />
                            </FormItem>
                        )}
                    />

                    <FormField
                        control={form.control}
                        name="description"
                        render={({ field }) => (
                            <FormItem className="w-full md:col-span-2">
                                <FormLabel className="flex items-center gap-2">
                                    <FileText className="w-4 h-4 text-muted-foreground" />
                                    {t("team_description_label")}
                                </FormLabel>
                                <FormControl>
                                    <Textarea 
                                        placeholder={t("team_description_placeholder")} 
                                        {...field} 
                                        className="min-h-[100px] resize-none border-none bg-primary/5 focus-visible:ring-1 focus-visible:ring-primary/50" 
                                    />
                                </FormControl>
                                <FormMessage />
                            </FormItem>
                        )}
                    />

                    <FormField
                        control={form.control}
                        name="logoFile"
                        render={({ field: { _value, onChange, ...fieldProps } }) => (
                            <FormItem className="w-full md:col-span-2">
                                <FormLabel className="flex items-center gap-2">
                                    <ImageIcon className="w-4 h-4 text-muted-foreground" />
                                    {t("team_logo_label") || "Team Logo"}
                                </FormLabel>
                                <FormControl>
                                    <div className="group relative">
                                        {!logoPreviewUrl ? (
                                            <div className="border-2 border-dashed border-muted-foreground/25 hover:border-primary/50 transition-colors rounded-none p-6 text-center cursor-pointer bg-muted/5 hover:bg-muted/10 relative">
                                                <Input
                                                    {...fieldProps}
                                                    type="file"
                                                    accept="image/*"
                                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                                                    onChange={(event) => {
                                                        const file = event.target.files && event.target.files[0];
                                                        if (file) {
                                                            onChange(event.target.files);
                                                            const reader = new FileReader();
                                                            reader.onloadend = () => {
                                                                setLogoPreviewUrl(reader.result as string);
                                                            };
                                                            reader.readAsDataURL(file);
                                                        }
                                                    }}
                                                />
                                                <div className="flex flex-col items-center gap-2">
                                                    <div className="p-2 bg-primary/10 rounded-none text-primary group-hover:scale-110 transition-transform">
                                                        <Upload className="w-4 h-4" />
                                                    </div>
                                                    <div className="text-sm font-medium text-foreground">
                                                        {t("click_to_upload_logo") || t("click_to_upload")}
                                                    </div>
                                                </div>
                                            </div>
                                        ) : (
                                            <div className="relative rounded-none overflow-hidden border bg-muted/30 p-2">
                                                <div className="flex items-center gap-3">
                                                    <div className="h-16 w-16 relative rounded-none overflow-hidden border bg-foreground">
                                                        <img src={logoPreviewUrl} alt="Logo preview" className="object-contain w-full h-full" />
                                                    </div>
                                                    <div className="flex-1 min-w-0">
                                                        <p className="text-sm font-medium truncate text-foreground">{t("logo_preview") || "Logo Preview"}</p>
                                                        <p className="text-xs text-muted-foreground">{t("ready_to_submit")}</p>
                                                    </div>
                                                    <Button
                                                        type="button"
                                                        variant="ghost"
                                                        size="icon"
                                                        className="text-muted-foreground hover:text-destructive"
                                                        onClick={() => {
                                                            onChange(undefined);
                                                            setLogoPreviewUrl(null);
                                                            setSelectedTeamId("new");
                                                        }}
                                                    >
                                                        <X className="w-4 h-4" />
                                                    </Button>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                </FormControl>
                                <FormMessage />
                            </FormItem>
                        )}
                    />

                    <FormField
                        control={form.control}
                        name="contactName"
                        render={({ field }) => (
                            <FormItem>
                                <FormLabel className="flex items-center gap-2">
                                    <User className="w-4 h-4 text-muted-foreground" />
                                    {t("contact_name_label")}
                                </FormLabel>
                                <FormControl>
                                    <Input placeholder={t("contact_name_placeholder")} {...field} className="h-11" />
                                </FormControl>
                                <FormMessage />
                            </FormItem>
                        )}
                    />

                    <FormField
                        control={form.control}
                        name="contactPhone"
                        render={({ field }) => (
                            <FormItem>
                                <FormLabel className="flex items-center gap-2">
                                    <Smartphone className="w-4 h-4 text-muted-foreground" />
                                    {t("contact_phone_label")}
                                </FormLabel>
                                <FormControl>
                                    <Input placeholder={t("contact_phone_placeholder")} {...field} className="h-11" />
                                </FormControl>
                                <FormMessage />
                            </FormItem>
                        )}
                    />
                </div>

                {!isFree && (
                    <>
                        <Separator />

                        <div className="bg-card border border-border/10 shadow-2xl rounded-none p-6 relative overflow-hidden">
                            <div className="absolute top-0 left-0 w-1 h-8 bg-secondary" />
                            <div className="bg-gradient-to-r from-secondary/10 to-transparent px-6 py-4 border-b border-border/10 relative -mx-6 -mt-6 mb-6">
                                <div className="absolute top-0 left-0 w-1 h-full bg-secondary" />
                                <h3 className="text-sm font-black italic uppercase tracking-widest text-secondary flex items-center gap-2">
                                    <Smartphone className="w-4 h-4" />
                                    {t("payment_details")}
                                </h3>
                            </div>
                            <p className="text-xs font-bold uppercase italic tracking-tighter text-muted-foreground/60 mb-6">
                                {t("scan_or_transfer")}
