                                <div className="flex flex-col h-full gap-6">
                                    <div className="bg-card border border-border/10 shadow-xl rounded-none p-6 space-y-4 text-sm relative overflow-hidden">
                                        <div className="absolute top-0 left-0 w-1 h-8 bg-secondary/30" />
                                        <div className="flex justify-between items-center pb-3 border-b border-border/5">
                                            <span className="text-[10px] uppercase font-black italic tracking-widest text-muted-foreground/40">{t("bank_label")}</span>
                                            <span className="font-black italic uppercase text-foreground">{tournament.bank_name || "-"}</span>
                                        </div>
                                        <div className="flex justify-between items-center pb-3 border-b border-border/5">
                                            <span className="text-[10px] uppercase font-black italic tracking-widest text-muted-foreground/40">{t("account_name_label")}</span>
                                            <span className="font-black italic uppercase text-foreground">{tournament.bank_account_name || "-"}</span>
                                        </div>
                                        <div className="flex justify-between items-center pt-1">
                                            <span className="text-[10px] uppercase font-black italic tracking-widest text-muted-foreground/40">{t("account_no_label")}</span>
                                            <span className="font-mono font-bold text-secondary text-lg leading-none tracking-tighter">{tournament.bank_account_number || "-"}</span>
                                        </div>
                                    </div>

                                    <FormField
                                        control={form.control}
                                        name="slipFile"
                                        render={({ field: { onChange, _value, ...rest } }) => (
                                            <FormItem className="flex-1 flex flex-col">
                                                <FormLabel className="flex items-center gap-2">
                                                    <FileText className="w-4 h-4 text-muted-foreground" />
                                                    {t("upload_slip_label")}
                                                </FormLabel>
                                                <FormControl className="flex-1">
                                                    <div className="group relative h-full flex flex-col">
                                                        {!slipPreviewUrl ? (
                                                            <div className="border-2 border-dashed border-muted-foreground/25 hover:border-primary/50 transition-colors rounded-none p-12 py-20 text-center cursor-pointer bg-muted/5 hover:bg-muted/10 relative flex-1 flex items-center justify-center min-h-[300px]">
                                                                <Input
                                                                    type="file"
                                                                    accept="image/jpeg,image/png,image/webp"
                                                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                                                                    onChange={(e) => {
                                                                        const file = e.target.files?.[0];
                                                                        if (file) {
                                                                            onChange(e.target.files);
                                                                            setSlipPreviewUrl(URL.createObjectURL(file));
                                                                        }
                                                                    }}
                                                                    {...rest}
                                                                />
                                                                <div className="flex flex-col items-center gap-4">
                                                                    <div className="p-4 bg-secondary/10 rounded-none text-secondary group-hover:scale-110 transition-transform shadow-[0_0_15px_rgba(var(--secondary),0.1)]">
                                                                        <Upload className="w-8 h-8" />
                                                                    </div>
                                                                    <div className="space-y-1">
                                                                        <div className="text-sm font-black italic uppercase tracking-widest text-foreground">
                                                                            {t("click_to_upload")}
                                                                        </div>
                                                                        <p className="text-[10px] font-bold uppercase italic tracking-widest text-muted-foreground/40">
                                                                            {t("file_types_hint")}
                                                                        </p>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        ) : (
                                                            <div className="relative rounded-none overflow-hidden border bg-muted/30 p-4">
                                                                <div className="flex flex-col gap-4">
                                                                    <div className="relative aspect-[3/4] w-full max-h-[400px] rounded-none overflow-hidden border bg-foreground flex items-center justify-center">
                                                                        <img
                                                                            src={slipPreviewUrl}
                                                                            alt="Slip preview"
                                                                            className="object-contain w-full h-full"
                                                                        />
                                                                        <Button
                                                                            type="button"
                                                                            variant="destructive"
                                                                            size="icon"
                                                                            className="absolute top-2 right-2 h-8 w-8 rounded-none shadow-md"
                                                                            onClick={() => {
                                                                                onChange(undefined);
                                                                                setSlipPreviewUrl(null);
                                                                            }}
                                                                        >
                                                                            <X className="w-4 h-4" />
                                                                        </Button>
                                                                    </div>
                                                                    <div className="flex items-center justify-between">
                                                                        <div className="flex-1 min-w-0">
                                                                            <p className="text-sm font-semibold truncate text-foreground">{t("slip_preview")}</p>
                                                                            <p className="text-xs text-muted-foreground">{t("ready_to_submit")}</p>
                                                                        </div>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        )}
                                                    </div>
                                                </FormControl>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />
                                </div>
                            </div>
                        </div>
                    </>
                )}

                <div className="pt-4">
                    <Button
                        type="submit"
                        disabled={isSubmitting || isRegistrationClosed}
                        className="w-full h-12 text-base font-semibold shadow-md active:scale-[0.99] transition-all"
                        size="lg"
                        variant={isRegistrationClosed ? "secondary" : "default"}
                    >
                        {isSubmitting ? (
                            <>
                                <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                                {isFree ? t("registering") : t("verifying_registering")}
                            </>
                        ) : isRegistrationClosed ? (
                            t("registration_closed_title")
                        ) : (
                            isFree ? t("confirm_registration") : t("confirm_and_pay")
                        )}
                    </Button>
                    <p className="text-center text-xs text-muted-foreground mt-4">
                        {isFree
                            ? t("terms_free")
                            : t("terms_paid")}
                    </p>
                </div>
            </form>
        </Form>
    );
}

'use client';

import React, { useState, useCallback, useEffect } from "react";
import { _ActionResponse, Player, GlobalPlayer, Team, SportType } from "@/types/index";
