"use client";

import { useState } from "react";
import { useTranslations } from "next-intl";
import { Match, Team } from "@/types/index";
import { MatchCard } from "@/components/tournaments/match-card";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { deleteMatch, advanceStage } from "@/actions/organizer/tournaments/general";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { Calendar, ArrowRight } from "lucide-react";
import { ExportToImageButton } from "@/components/ui/export-to-image-button";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";

interface FixturesManagerProps {
    teams: Team[];
    matches: Match[];
    tournamentId: string;
    goals?: any[]; // Using any[] or Goal[] if imported
    format?: string;
    isPro?: boolean;
}

export function FixturesManager({ matches, teams, tournamentId, _format, goals = [], isPro = false }: FixturesManagerProps) {
    const t = useTranslations("Tournament");
    const tMatch = useTranslations("Match");
    const tFixtures = useTranslations("Fixtures");
    const tBracket = useTranslations("Bracket");
    const [isEditMode, setIsEditMode] = useState(false);
    const [_filterRound, _setFilterRound] = useState<string>("all");
    const [filterStage, setFilterStage] = useState<string>("all");
    const [isAdvancing, setIsAdvancing] = useState(false);
    const [advanceDialogOpen, setAdvanceDialogOpen] = useState(false);

    // Calculate Max Group Round
    const _maxGroupRound = matches.reduce((max, m) => {
        if (m.stage === 'group' && (m.round || 0) > max) return m.round || 0;
        return max;
    }, 0);

    // Filter Logic
    const filteredMatches = matches.filter(match => {
        if (filterStage === "all") return true;

        if (filterStage.startsWith("Group")) {
            const groupLetter = filterStage.split(" ")[1];
            // Match must be in 'group' stage AND involve a team from that group (or both)
            if (match.stage !== 'group') return false;

            const homeGroup = teams.find(t => t.id === match.home_team_id)?.group_name;
            const awayGroup = teams.find(t => t.id === match.away_team_id)?.group_name;

            return homeGroup === groupLetter || awayGroup === groupLetter;
        }

        return match.stage === filterStage;
    });

    // Group matches by round
    const _matchesByRound = (filteredMatches || []).reduce((acc: Record<number, Match[]>, match: Match) => {
        const round = match.round;
        if (!acc[round]) {
            acc[round] = [];
        }
        acc[round].push(match);
        return acc;
    }, {});

    const _handleDelete = async (matchId: string) => {
        if (confirm(tFixtures("confirm_delete_match"))) {
            await deleteMatch(matchId, tournamentId);
        }
    };

    const handleAdvance = async () => {
        setAdvanceDialogOpen(false);
        setIsAdvancing(true);
        try {
            const result = await advanceStage(tournamentId);
            if (!result.success) {
                alert(result.error); // Or toast.error
            } else {
                // Success - UI will update via server action revalidate
            }
        } catch (error) {
            console.error(error);
            alert("Failed to advance stage");
        } finally {
            setIsAdvancing(false);
        }
    };

    return (
        <div className="space-y-4 md:space-y-6">
            {matches.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-12 text-center bg-foreground/5 border border-foreground/5 group relative overflow-hidden">
                    <div className="absolute left-0 top-0 w-1 h-0 bg-secondary group-hover:h-full transition-all duration-500" />
                    <div className="h-16 w-16 rounded-none bg-foreground/5 flex items-center justify-center mb-6 border border-foreground/10 group-hover:border-secondary/30 transition-colors">
                        <Calendar className="h-8 w-8 text-muted-foreground/40 group-hover:text-secondary transition-colors" />
                    </div>
                    <h3 className="text-xl font-black uppercase italic tracking-tighter text-foreground mb-2">{tFixtures("ready_to_start")}</h3>
                    <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground/40 max-w-xs leading-relaxed">
                        {tFixtures("generate_instruction")}
                    </p>
                </div>
            ) : (
                <>
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-2 md:gap-3 bg-foreground/5 p-4 md:p-6 border border-foreground/5">
                    {/* Filter Area */}
                    <div className="flex flex-wrap items-center gap-2 md:gap-3">
                        <div className="space-y-1">
                            <Label className="text-[10px] font-black uppercase tracking-wider text-muted-foreground/60">{tMatch("status")}</Label>
                            <Select value={filterStage} onValueChange={setFilterStage}>
                                <SelectTrigger className="h-10 w-[200px] bg-card border-foreground/10 rounded-none focus:ring-secondary/50 font-bold uppercase italic tracking-tighter text-xs">
                                    <SelectValue placeholder={tMatch("round")} />
                                </SelectTrigger>
                                <SelectContent className="bg-card border-foreground/10 rounded-none">
                                    <SelectItem value="all" className="hover:bg-foreground/5 focus:bg-foreground/5 uppercase italic font-bold text-xs">{tMatch("round")} ({tMatch("all")})</SelectItem>
                                    <SelectItem value="group" className="hover:bg-foreground/5 focus:bg-foreground/5 uppercase italic font-bold text-xs">{tMatch("group")}</SelectItem>
                                    <SelectItem value="Group A" className="hover:bg-foreground/5 focus:bg-foreground/5 uppercase italic font-bold text-xs">{tMatch("group")} A</SelectItem>
                                    <SelectItem value="Group B" className="hover:bg-foreground/5 focus:bg-foreground/5 uppercase italic font-bold text-xs">{tMatch("group")} B</SelectItem>
                                    <SelectItem value="Group C" className="hover:bg-foreground/5 focus:bg-foreground/5 uppercase italic font-bold text-xs">{tMatch("group")} C</SelectItem>
                                    <SelectItem value="Group D" className="hover:bg-foreground/5 focus:bg-foreground/5 uppercase italic font-bold text-xs">{tMatch("group")} D</SelectItem>
                                    <SelectItem value="round_of_16" className="hover:bg-foreground/5 focus:bg-foreground/5 uppercase italic font-bold text-xs">{tMatch("round_of_16")}</SelectItem>
                                    <SelectItem value="quarter_final" className="hover:bg-foreground/5 focus:bg-foreground/5 uppercase italic font-bold text-xs">{tMatch("quarter_final")}</SelectItem>
                                    <SelectItem value="semi_final" className="hover:bg-foreground/5 focus:bg-foreground/5 uppercase italic font-bold text-xs">{tMatch("semi_final")}</SelectItem>
                                    <SelectItem value="final" className="hover:bg-foreground/5 focus:bg-foreground/5 uppercase italic font-bold text-xs">{tMatch("final")}</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>

                    <div className="flex items-center gap-2 md:gap-3">
                        <div className="flex items-center gap-2 md:gap-3">
                            <Switch 
                                id="edit-mode" 
                                checked={isEditMode} 
                                onCheckedChange={setIsEditMode}
                                className="data-[state=checked]:bg-secondary" 
                            />
                            <Label htmlFor="edit-mode" className="text-[10px] font-black uppercase tracking-wider text-muted-foreground cursor-pointer">
                                {t("edit_mode") || "Edit Mode"}
                            </Label>
                        </div>
                        <ExportToImageButton 
                            targetId="fixtures-canvas" 
                            filename="fixtures" 
                            label={t("export") || "Export"}
                        />
                    </div>
                </div>

            <div id="fixtures-canvas" className="space-y-4 md:space-y-6">
                {filteredMatches.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-12 text-center bg-foreground/5 border border-foreground/5">
                        <Calendar className="h-12 w-12 text-muted-foreground/20 mb-4" />
                        <h3 className="text-sm font-black uppercase italic tracking-tighter text-muted-foreground/40">{tFixtures("no_fixtures")}</h3>
                    </div>
                ) : (
                    (() => {
                        const groups = filteredMatches.reduce((acc: Record<string, Match[]>, match) => {
                            const isKnockout = match.stage !== 'group' && match.stage !== 'league';
                            const key = isKnockout ? match.stage : 'group_stage';
                            if (!acc[key]) acc[key] = [];
                            acc[key].push(match);
                            return acc;
                        }, {});

                        const sortedKeys = Object.keys(groups).sort((a, b) => {
                            if (a === 'group_stage') return -1;
                            if (b === 'group_stage') return 1;

                            const aRound = groups[a][0].round || 0;
                            const bRound = groups[b][0].round || 0;
                            return aRound - bRound;
                        });

                        return sortedKeys.map((key) => {
                            const stageMatches = groups[key];
                            const firstMatch = stageMatches[0];
                            const stage = firstMatch.stage;

                            let headerText = "";
                            if (key === 'group_stage') {
                                headerText = "";
                            } else {
                                if (stage === 'round_of_16') headerText = tBracket("round_of_16");
                                else if (stage === 'quarter_final') headerText = tBracket("quarter_final");
                                else if (stage === 'semi_final') headerText = tBracket("semi_final");
                                else if (stage === 'final') headerText = tBracket("final");
                                else headerText = stage?.replace('_', ' ').toUpperCase() || "";
                            }

                            return (
                                <div key={key} className="space-y-4 md:space-y-6">
                                    {headerText && (
                                        <div className="flex items-center gap-2 md:gap-3">
                                            <div className="h-px bg-secondary/30 flex-1" />
                                            <h3 className="text-[11px] font-black uppercase tracking-[0.3em] text-secondary">
                                                {headerText}
                                            </h3>
                                            <div className="h-px bg-secondary/30 flex-1" />
                                        </div>
                                    )}
                                    <div className="space-y-[1px] bg-foreground/5 border border-foreground/5">
                                        {[...stageMatches]
                                            .sort((a, b) => {
                                                if (a.round !== b.round) return (a.round || 0) - (b.round || 0);
                                                if (a.match_date !== b.match_date) return (a.match_date || "") > (b.match_date || "") ? 1 : -1;
                                                if (a.match_time !== b.match_time) return (a.match_time || "") > (b.match_time || "") ? 1 : -1;
                                                return 0;
                                            })
                                            .map((match) => (
                                                <div key={match.id} className="relative group overflow-hidden">
                                                    <MatchCard
                                                        match={match}
                                                        tournamentId={tournamentId}
                                                        goals={goals.filter((g: any) => g.match_id === match.id)}
                                                        isEditMode={isEditMode}
                                                        teams={teams}
                                                        isPro={isPro}
                                                    />
                                                </div>
                                            ))
                                        }
                                    </div>

                                    {/* Proceed to Knockout Button - Styled for Sidebar potentially, but keep here for now if matches are listed */}
                                    {key === 'group_stage' && matches.some(m => m.stage === 'group') && !matches.some(m => m.stage !== 'group' && m.stage !== 'league') && (
                                        <div className="flex justify-center pt-4 md:pt-6">
                                            <Button
                                                onClick={() => setAdvanceDialogOpen(true)}
                                                disabled={isAdvancing}
                                                className="h-14 px-4 md:px-6 bg-secondary text-secondary-foreground font-black uppercase italic tracking-tighter hover:bg-secondary/90 shadow-lg shadow-secondary/10 group transition-all"
                                            >
                                                {isAdvancing ? tFixtures("generating") : (
                                                    <span className="flex items-center gap-3">
                                                        {tFixtures("proceed_knockout")} 
                                                        <ArrowRight className="h-5 w-5 group-hover:translate-x-1 transition-transform" />
                                                    </span>
                                                )}
                                            </Button>
                                        </div>
                                    )}
                                </div>
                            );
                        });
                    })()
                )}
            </div>
            </>
            )}

            <AlertDialog open={advanceDialogOpen} onOpenChange={setAdvanceDialogOpen}>
                <AlertDialogContent className="bg-card border-border/10 rounded-none shadow-2xl max-w-md">
                    <AlertDialogHeader>
                        <AlertDialogTitle className="text-xl font-black uppercase italic tracking-tighter text-foreground flex items-center gap-2">
                            <ArrowRight className="h-5 w-5 text-secondary" />
                            {tFixtures("proceed_knockout")}
                        </AlertDialogTitle>
                        <AlertDialogDescription className="text-sm font-medium text-muted-foreground/80 mt-2">
                            {tFixtures("confirm_advance_knockout")}
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter className="mt-6">
                        <AlertDialogCancel className="rounded-none border-border/10 bg-foreground/5 hover:bg-foreground/10 hover:text-foreground transition-all h-10 text-[11px] font-black uppercase tracking-widest">
                            {t("cancel") || "Cancel"}
                        </AlertDialogCancel>
                        <AlertDialogAction
                            onClick={(e) => {
                                e.preventDefault();
                                handleAdvance();
                            }}
                            className="rounded-none border border-secondary/20 bg-secondary/90 text-secondary-foreground hover:bg-secondary hover:shadow-[0_0_15_rgba(0,255,157,0.3)] transition-all h-10 text-[11px] font-black uppercase tracking-widest"
                        >
                            <ArrowRight className="h-3.5 w-3.5 mr-2" />
                            {tFixtures("proceed") || "Proceed"}
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { formatDate } from "@/lib/date";
import { useLocale, useTranslations } from "next-intl";
import { useSearchParams } from "next/navigation";
import { _CalendarIcon, _MapPin, _Clock, _Trophy, Eraser, ChevronRight } from "lucide-react";
import { Match, Goal, Team, MatchEvent } from "@/types/index";
import { updateMatch, _deleteMatch } from "@/actions/organizer/tournaments/general";
import { Button } from "@/components/ui/button";
import { _Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { cn } from "@/lib/utils";
import { Link } from "@/i18n/routing";
import { createClient } from "@/lib/supabase/client";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";

// ...

export function MatchCard({ match: initialMatch, tournamentId, _goals = [], isPublic = false, isEditMode = false, teams = [], _isPro = false, _initialEvents = [] }: { match: Match; tournamentId: string; goals?: Goal[]; isPublic?: boolean; isEditMode?: boolean; teams?: Team[]; isPro?: boolean; initialEvents?: MatchEvent[] }) {
    const t = useTranslations("Fixtures");
    const tMatch = useTranslations("Match");
    const tCommon = useTranslations("Common");
    const locale = useLocale();
    const searchParams = useSearchParams();

    const [isLoading, setIsLoading] = useState(false);
    const [clearDialogOpen, setClearDialogOpen] = useState(false);

    // --- Realtime Sync State ---
    const [match, setMatchState] = useState<Match>(initialMatch);

    // Update local state if prop changes
    useEffect(() => {
        setMatchState(initialMatch);
    }, [initialMatch]);

    // Supabase Realtime Subscription
    useEffect(() => {
        const supabase = createClient();
        const channel = supabase
            .channel(`match-card-${match.id}`)
            .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'matches', filter: `id=eq.${match.id}` }, (payload) => {
                setMatchState(payload.new as Match);
                // No router.refresh() here to avoid full page reloads on every card update, local state is enough for the card itself
            })
            .subscribe();

        return () => { supabase.removeChannel(channel); };
    }, [match.id]);

    // Local state for auto-save inputs
    const [matchDate, setMatchDate] = useState(match.match_date || "");
    const [matchTime, setMatchTime] = useState(match.match_time || "");

    const handleDateUpdate = async (newDate: string) => {
        setMatchDate(newDate);
        if (newDate !== match.match_date) {
            await updateMatch(match.id, { match_date: newDate }, tournamentId);
        }
    };

    const handleTimeUpdate = async (newTime: string) => {
        setMatchTime(newTime);
        if (newTime !== match.match_time) {
            await updateMatch(match.id, { match_time: newTime }, tournamentId);
        }
    };

    // Running Timer Logic
    const [_elapsedTime, setElapsedTime] = useState<string>("");

    useEffect(() => {
        if (match.status === 'live') {
            const calculateTime = () => {
                if (match.timer_status === 'paused' && match.elapsed_before_pause !== undefined) {
                    // Paused: Static time from snapshot
                    const totalSeconds = match.elapsed_before_pause;
                    const mins = Math.floor(totalSeconds / 60);
                    const secs = totalSeconds % 60;
                    setElapsedTime(`${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`);
                } else if (match.match_date && match.match_time) {
                    // Playing: Calc diff from Last Resume Time + specific elapsed history
                    const now = new Date();
                    const start = new Date(`${match.match_date}T${match.match_time}`);
                    const extraSeconds = match.elapsed_before_pause || 0;

                    const diffMs = now.getTime() - start.getTime();
                    const totalSeconds = Math.max(0, Math.floor(diffMs / 1000) + extraSeconds);

                    const mins = Math.floor(totalSeconds / 60);
                    const secs = totalSeconds % 60;

                    setElapsedTime(`${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`);
                }
            };

            calculateTime(); // Initial Update

            // Run interval ONLY if playing
            if (match.timer_status !== 'paused') {
                const interval = setInterval(calculateTime, 1000);
                return () => clearInterval(interval);
            }
        } else {
            setElapsedTime("");
        }
    }, [match.status, match.match_date, match.match_time, match.timer_status, match.elapsed_before_pause]);

    // Helper Variables
    const status = match.status?.toLowerCase() || 'scheduled';
    const isLive = status === 'live';
    const isFinished = status === 'finished';
    const isTie = isFinished && (match.home_score === match.away_score);

    // Format Date Helper
    // Use global formatDate helper
    // const formatDate = ... (removed)

    // Format Time Helper (24H)
    const formatTime = (timeStr?: string | null) => {
        if (!timeStr) return null;
        // Assume timeStr is HH:mm:ss or HH:mm
        const [h, m] = timeStr.split(':');
        return `${h.padStart(2, '0')}:${m}`;
    };

    // Tie Breaker Logic (α╕ûα╣ëα╕▓α╕òα╣ëα╕¡α╕çα╕üα╕▓α╕úα╣âα╕½α╣ëα╣Çα╕Ñα╕╖α╕¡α╕üα╕£α╕╣α╣ëα╕èα╕Öα╕░α╣Çα╕íα╕╖α╣êα╕¡α╣Çα╕¬α╕íα╕¡α╣âα╕Öα╕úα╕¡α╕Ü Knockout)
    const _showTieBreaker = isTie && (
        match.stage?.includes('knockout') ||
        match.stage === 'quarter_final' ||
        match.stage === 'semi_final' ||
        match.stage === 'final'
    );

    const _handleSelectWinner = async (winnerId: string | null) => {
        if (!winnerId) return;
        setIsLoading(true);
        try {
            await updateMatch(match.id, { winner_id: winnerId }, tournamentId);
        } catch (_error) {
            console.error("Failed to set winner");
        } finally {
            setIsLoading(false);
        }
    };

    const handleClear = async () => {
        setClearDialogOpen(false);
        setIsLoading(true);
        try {
            await updateMatch(match.id, {
                home_team_id: null,
                away_team_id: null,
                home_score: null,
                away_score: null,
                winner_id: null,
                status: 'scheduled'
            }, tournamentId);
        } catch (_error) {
            console.error("Failed to clear match");
        } finally {
            setIsLoading(false);
        }
    };

    const CardContent = (
        <div
            className={cn(
                "flex flex-col md:grid md:grid-cols-[160px_1fr_120px] items-center px-4 md:px-6 py-2 md:py-4 transition-all cursor-pointer group relative overflow-hidden",
                isFinished ? "bg-[#050505]/60" : "bg-transparent hover:bg-foreground/5",
                "gap-4",
                isLive && "bg-secondary/5"
            )}
        >
            {/* Live Indicator Bar */}
            {isLive && <div className="absolute left-0 top-0 bottom-0 w-1 bg-secondary animate-pulse" />}

            {/* 1. Status/Time/Badge Section */}
            <div className="flex flex-col items-center justify-center w-full md:w-auto md:items-start md:justify-start gap-2 min-w-[120px]">
                {status !== 'scheduled' && (
                    <div
                        className={cn(
                            "uppercase text-[9px] tracking-[0.2em] font-black px-3 py-1 border-l-2",
                            status === 'scheduled' && "text-muted-foreground/40 border-muted-foreground/20",
                            isLive && "text-secondary border-secondary animate-pulse",
                            isFinished && "text-muted-foreground/60 border-muted-foreground/30",
                            !match.away_team_id && "text-muted-foreground/40 border-muted-foreground/20"
                        )}
                    >
                        {!match.away_team_id ? t("scheduled") : (
                            isLive ? (
                                <span className="flex items-center gap-2">
                                    <span className="relative flex h-1.5 w-1.5">
                                        <span className="animate-ping absolute inline-flex h-full w-full rounded-none bg-secondary opacity-75"></span>
                                        <span className="relative inline-flex rounded-none h-1.5 w-1.5 bg-secondary"></span>
                                    </span>
                                    {match.current_minute ? (
                                        typeof match.current_minute === 'number' ? `${match.current_minute}'` : match.current_minute
                                    ) : t("live")}
                                </span>
                            ) : (
                                isFinished ? t("ft") : t("scheduled")
                            )
                        )}
                    </div>
                )}

                {/* Date/Time Info (Edit Mode only) */}
                {!isFinished && !isLive && !isPublic && isEditMode && (
                    <div className="w-full">
                        <div className="flex flex-col gap-2 w-full" onClick={(e) => e.stopPropagation()}>
                            <Input
                                type="date"
                                className="h-8 bg-[#0A0A0A] border-foreground/5 rounded-none text-[10px] font-black uppercase italic tracking-tighter"
                                value={matchDate}
                                onChange={(e) => handleDateUpdate(e.target.value)}
                            />
                            <Input
                                type="time"
                                className="h-8 bg-[#0A0A0A] border-foreground/5 rounded-none text-[10px] font-black uppercase italic tracking-tighter"
                                value={formatTime(matchTime) || ""}
                                onChange={(e) => handleTimeUpdate(e.target.value)}
                            />
                        </div>
                    </div>
                )}
            </div>

            {/* 2. Teams & Score Section */}
            <div className="flex flex-row items-center justify-between w-full gap-4 md:gap-8">

                {/* Home Team */}
                <div className="flex-1 flex items-center justify-end gap-3 md:gap-6 text-right w-[40%]">
                    <div className={cn(
                        "text-base md:text-2xl font-black uppercase italic tracking-tighter flex items-center gap-3 justify-end group-hover:text-secondary transition-colors duration-300",
                        (isFinished && (match.home_score ?? -1) > (match.away_score ?? -1)) || match.winner_id === match.home_team_id ? "text-foreground" : "text-muted-foreground/60"
                    )}>
                        {isEditMode ? (
                            <div onClick={e => e.stopPropagation()}>
                                <Select
                                    value={match.home_team_id || "tbd"}
                                    onValueChange={(value) => updateMatch(match.id, { home_team_id: value === "tbd" ? "" : value }, tournamentId)}
                                >
                                    <SelectTrigger className="h-10 w-[120px] md:w-[180px] bg-[#0A0A0A] border-foreground/5 rounded-none focus:ring-secondary/50 font-black uppercase italic tracking-tighter text-xs">
                                        <SelectValue placeholder={tMatch("select_team")} />
                                    </SelectTrigger>
                                    <SelectContent className="bg-[#111] border-foreground/5">
                                        <SelectItem value="tbd" className="font-black italic uppercase text-xs">{tMatch("tbd")}</SelectItem>
                                        {teams.map((t) => (
                                            <SelectItem key={t.id} value={t.id} className="font-black italic uppercase text-xs">{t.name}</SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </div>
                        ) : (
                            <>
                                <span className={cn(
                                    "line-clamp-1 py-1 px-2 text-foreground",
                                    (isFinished && (match.home_score ?? -1) > (match.away_score ?? -1)) && "bg-secondary/10"
                                )}>
                                    {match.home_team?.name || tMatch("tbd")}
                                </span>
                                {match.home_team?.logo_url ? (
                                    <img src={match.home_team.logo_url} className="w-8 h-8 md:w-12 md:h-12 object-contain grayscale-[0.2] group-hover:grayscale-0 transition-all" alt="" />
                                ) : (
                                    <div className="w-8 h-8 md:w-12 md:h-12 rounded-none bg-foreground/5 flex items-center justify-center shrink-0 border border-foreground/5">
                                        <span className="text-[10px] md:text-xs font-black text-muted-foreground/40">
                                            {match.home_team?.name?.substring(0, 2).toUpperCase() || "?"}
                                        </span>
                                    </div>
                                )}
                            </>
                        )}
                    </div>
                </div>

                {/* Score Box */}
                <div className="flex items-center justify-center shrink-0">
                    <div className={cn(
                        "flex flex-col items-center justify-center transition-all duration-300",
                        isLive ? " text-secondary-foreground scale-110" : 
                        isFinished ? " text-foreground" : " text-muted-foreground/40"
                    )}>
                        {isLive || isFinished ? (
                            <div className="flex flex-col w-[5rem] items-center leading-none">
                                <div className="flex items-center gap-1 md:gap-3">
                                    <span className="text-xl md:text-3xl font-black text-foreground italic tracking-tighter">
                                        {match.home_score ?? 0}
                                    </span>
                                    <span className="text-muted-foreground/20 font-black italic">-</span>
                                    <span className="text-xl md:text-3xl font-black text-foreground italic tracking-tighter">
                                        {match.away_score ?? 0}
                                    </span>
                                </div>
                                {((match.penalty_home_score ?? 0) > 0 || (match.penalty_away_score ?? 0) > 0) && (
                                    <span className="text-[8px] font-black uppercase tracking-tighter mt-1 opacity-60 italic">
                                        ({match.penalty_home_score ?? 0}-{match.penalty_away_score ?? 0} PK)
                                    </span>
                                )}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center min-w-[5rem] group-hover:scale-110 transition-transform duration-300">
                                <span className="text-lg md:text-xl font-black text-foreground italic tracking-tighter leading-none hover:text-secondary transition-colors">
                                    {formatTime(match.match_time) || "--:--"}
                                </span>
                                {match.match_date && (
                                    <span className="text-[9px] font-bold text-muted-foreground/40 uppercase tracking-[0.1em] mt-1 leading-none">
                                        {formatDate(match.match_date, "d MMM", locale)}
                                    </span>
                                )}
                            </div>
                        )}
                    </div>
                </div>

                {/* Away Team */}
                <div className="flex-1 flex items-center justify-start gap-3 md:gap-6 text-left w-[40%]">
                    <div className={cn(
                        "text-base md:text-2xl font-black uppercase italic tracking-tighter flex items-center gap-3 justify-start group-hover:text-secondary transition-colors duration-300",
                        (isFinished && (match.away_score ?? -1) > (match.home_score ?? -1)) || match.winner_id === match.away_team_id ? "text-foreground" : "text-muted-foreground/60"
                    )}>
                        {isEditMode ? (
                            <div onClick={e => e.stopPropagation()}>
                                <Select
                                    value={match.away_team_id || "tbd"}
                                    onValueChange={(value) => updateMatch(match.id, { away_team_id: value === "tbd" ? "" : value }, tournamentId)}
                                >
                                    <SelectTrigger className="h-10 w-[120px] md:w-[180px] bg-[#0A0A0A] border-foreground/5 rounded-none focus:ring-secondary/50 font-black uppercase italic tracking-tighter text-xs">
                                        <SelectValue placeholder={tMatch("select_team")} />
                                    </SelectTrigger>
                                    <SelectContent className="bg-[#111] border-foreground/5">
                                        <SelectItem value="tbd" className="font-black italic uppercase text-xs">{tMatch("tbd")}</SelectItem>
                                        {teams.map((t) => (
                                            <SelectItem key={t.id} value={t.id} className="font-black italic uppercase text-xs">{t.name}</SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </div>
                        ) : (
                            <>
                                {match.away_team?.logo_url ? (
                                    <img src={match.away_team.logo_url} className="w-8 h-8 md:w-12 md:h-12 object-contain grayscale-[0.2] group-hover:grayscale-0 transition-all" alt="" />
                                ) : (
                                    <div className="w-8 h-8 md:w-12 md:h-12 rounded-none bg-foreground/5 flex items-center justify-center shrink-0 border border-foreground/5">
                                        <span className="text-[10px] md:text-xs font-black text-muted-foreground/40">
                                            {match.away_team?.name?.substring(0, 2).toUpperCase() || "?"}
                                        </span>
                                    </div>
                                )}
                                <span className={cn(
                                    "line-clamp-1 py-1 px-2 text-foreground",
                                    (isFinished && (match.away_score ?? -1) > (match.home_score ?? -1)) && "bg-secondary/10"
                                )}>
                                    {match.away_team?.name || tMatch("tbd")}
                                </span>
                            </>
                        )}
                    </div>
                </div>
            </div>

            {/* 3. Actions / Selection Indicator */}
            <div className="flex items-center justify-end md:ml-auto" onClick={e => e.stopPropagation()}>
                {isEditMode && match.away_team_id && (
                    <Button
                        size="icon"
                        variant="ghost"
                        className="h-10 w-10 text-muted-foreground/20 hover:text-destructive hover:bg-destructive/10 rounded-none transition-colors"
                        onClick={() => setClearDialogOpen(true)}
                        disabled={isLoading}
                    >
                        <Eraser className="h-4 w-4" />
                    </Button>
                )}

                {/* Arrow indicator for drill-down */}
                <div className="mx-2 hidden md:block">
                    <ChevronRight className="h-4 w-4 text-muted-foreground/10 group-hover:text-secondary group-hover:translate-x-1 transition-all" />
                </div>
            </div>
        </div>
    );

    // If there is an away team, the card is clickable to open the full page console
    const canOpen = isPublic || !!match.away_team_id;
    const currentTab = searchParams.get('tab');
    const querySuffix = currentTab ? `?from=${currentTab}` : '';

    const url = isPublic 
        ? `/${tournamentId}/matches/${match.id}${querySuffix}`
        : `/organizer/tournaments/${tournamentId}/matches/${match.id}${querySuffix}`;

    return (
        <>
            {canOpen ? (
                <Link href={url} className="block transition-transform hover:scale-[1.01]">
                    {CardContent}
                </Link>
            ) : CardContent}

            <AlertDialog open={clearDialogOpen} onOpenChange={setClearDialogOpen}>
                <AlertDialogContent className="bg-card border-border/10 rounded-none shadow-2xl max-w-md">
                    <AlertDialogHeader>
                        <AlertDialogTitle className="text-xl font-black uppercase italic tracking-tighter text-foreground flex items-center gap-2">
                            <Eraser className="h-5 w-5 text-destructive" />
                            {t("clear_match") || "Clear Match"}
                        </AlertDialogTitle>
                        <AlertDialogDescription className="text-sm font-medium text-muted-foreground/80 mt-2">
                            {t("confirm_clear")}
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter className="mt-6">
                        <AlertDialogCancel className="rounded-none border-border/10 bg-foreground/5 hover:bg-foreground/10 hover:text-foreground transition-all h-10 text-[11px] font-black uppercase tracking-widest">
                            {tCommon("cancel")}
                        </AlertDialogCancel>
                        <AlertDialogAction
                            onClick={(e) => {
                                e.preventDefault();
                                handleClear();
                            }}
                            className="rounded-none border border-destructive/20 bg-destructive/90 text-foreground hover:bg-destructive hover:shadow-[0_0_15_rgba(220,38,38,0.3)] transition-all h-10 text-[11px] font-black uppercase tracking-widest"
                        >
                            <Eraser className="h-3.5 w-3.5 mr-2" />
                            {t("clear") || "Clear"}
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </>
    );
}

"use client";

import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { PlayerStat } from "@/lib/player-stats";
import { AlertTriangle, Shield } from "lucide-react";
import { useTranslations } from "next-intl";

interface PlayerStatsTableProps {
    stats: PlayerStat[];
}

export function PlayerStatsTable({ stats }: PlayerStatsTableProps) {
    const t = useTranslations("PlayerStats");

    if (stats.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center py-12 text-center border border-dashed rounded-none bg-muted/10">
                <div className="h-12 w-12 rounded-none bg-muted/20 flex items-center justify-center mb-4">
                    <Shield className="h-6 w-6 text-muted-foreground" />
                </div>
                <h3 className="text-sm font-medium text-muted-foreground">{t("no_stats")}</h3>
            </div>
        );
    }

    return (
        <div className="w-full overflow-x-auto rounded-none border">
            <Table className="min-w-[600px] text-xs md:text-sm">
                <TableHeader>
                    <TableRow className="h-8 md:h-10">
                        <TableHead className="w-8 text-center px-0">#</TableHead>
                        <TableHead className="px-0">{t("player")}</TableHead>
                        <TableHead className="px-0">{t("team")}</TableHead>
                        <TableHead className="text-center px-0">{t("mp")}</TableHead>
                        <TableHead className="text-center px-0">{t("goals")}</TableHead>
                        <TableHead className="text-center px-0">{t("assists")}</TableHead>
                        <TableHead className="text-center px-0">{t("yellow_cards")}</TableHead>
                        <TableHead className="text-center px-0">{t("red_cards")}</TableHead>
                        <TableHead className="text-center px-0">{t("status")}</TableHead>
                    </TableRow>
                </TableHeader>
                <TableBody>
                    {stats.map((stat, index) => (
