                                                                    <SelectValue placeholder="POS" />
                                                                </SelectTrigger>
                                                                <SelectContent className="rounded-none border-border">
                                                                    <SelectItem value="FW" className="text-[9px] font-black uppercase tracking-widest">{t("forward") || "FW"}</SelectItem>
                                                                </SelectContent>
                                                            </Select>
                                                        ) : (
                                                            <Badge className="rounded-none bg-muted border-none text-muted-foreground text-[9px] font-black uppercase tracking-widest px-2 py-0.5">
                                                                {player.position || "N/A"}
                                                            </Badge>
                                                        )}

                                                        {(editingPlayerId === player.id && !player.global_player_id) ? (
                                                            <Input
                                                                value={editBirthDate}
                                                                onChange={e => setEditBirthDate(e.target.value)}
                                                                type="date"
                                                                lang={locale === 'th' ? 'th-TH' : 'en-US'}
                                                                className="h-7 w-28 border-t-0 border-x-0 border-border/40 bg-muted/10 text-[9px] font-black p-1 focus-visible:ring-0 uppercase shadow-none"
                                                            />
                                                        ) : (
                                                            player.birth_date && (
                                                                <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground/40 font-mono">
                                                                    {formatDate(player.birth_date)}
                                                                </span>
                                                            )
                                                        )}
                                                    </div>
                                                </div>

                                                <div className="flex items-center gap-4 mt-3">
                                                    {!player.global_player_id && !readOnly && (
                                                        <Popover
                                                            open={linkingPlayerId === player.id}
                                                            onOpenChange={(isOpen) => {
                                                                setLinkingPlayerId(isOpen ? player.id : null);
                                                                if (isOpen) {
                                                                    setSearchQuery("");
                                                                    handleSearch("");
                                                                } else {
                                                                    setSearchQuery("");
                                                                    setSearchResults([]);
                                                                }
                                                            }}
                                                        >
                                                            <PopoverTrigger asChild>
                                                                <Button variant="link" size="sm" className="p-0 h-auto text-[10px] font-black uppercase tracking-widest text-secondary hover:text-secondary/80 flex items-center gap-2">
                                                                    <Link2 className="h-3.5 w-3.5" />
                                                                    {tCommon("search")} Global ID
                                                                </Button>
                                                            </PopoverTrigger>
                                                            <PopoverContent className="w-80 p-0 rounded-none border-border bg-card shadow-2xl" align="start">
                                                                <div className="p-0 border-b border-border/40">
                                                                    <div className="relative group/search">
                                                                        <div className="relative">
                                                                            <Search className="absolute left-5 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground/30 group-focus-within/search:text-secondary group-focus-within/search:scale-110 transition-all duration-300 z-10" />
                                                                            <Input
                                                                                placeholder="Start typing..."
                                                                                value={searchQuery}
                                                                                onChange={(e) => handleSearch(e.target.value)}
                                                                                className="pl-14 h-16 text-xs bg-muted/5 border-none rounded-none group-focus-within/search:bg-muted/10 transition-all duration-500 font-black uppercase italic tracking-widest placeholder:text-muted-foreground/20 focus-visible:ring-0 shadow-none relative z-10"
                                                                                autoFocus
                                                                            />
                                                                            <div className="absolute bottom-0 left-0 w-0 h-[2px] bg-secondary group-focus-within/search:w-full transition-all duration-700 z-20" />
