                            <TableCell className="text-center px-4 font-bold text-muted-foreground/30 tabular-nums border-b border-border/5">{team.ga}</TableCell>
                            <TableCell className={`text-center px-4 font-black italic text-sm tabular-nums border-b border-border/5 ${team.gd > 0 ? "text-primary" : team.gd < 0 ? "text-destructive" : "text-muted-foreground/40"}`}>
                                {team.gd > 0 ? `+${team.gd}` : team.gd}
                            </TableCell>
                            <TableCell className="text-center px-6 sticky right-0 z-10 bg-background group-hover:bg-muted/10 transition-colors font-black text-lg text-foreground border-b border-border/5 border-l border-border/5 tabular-nums">
                                {team.pts}
                            </TableCell>
                        </TableRow>
                    ))}
                    {standings.length === 0 && (
                        <TableRow>
                            <TableCell colSpan={10} className="text-center py-20 bg-muted/2">
                                <div className="flex flex-col items-center justify-center gap-4">
                                    <div className="h-16 w-16 rounded-none bg-muted/10 border border-border/10 flex items-center justify-center relative group">
                                        <div className="absolute top-0 left-0 w-1 h-full bg-muted/20" />
                                        <List className="h-8 w-8 text-muted-foreground/20 group-hover:text-muted-foreground/40 transition-colors" />
                                    </div>
                                    <div className="space-y-1">
                                        <h3 className="text-sm font-black uppercase italic tracking-widest text-muted-foreground/40">{t("no_stats")}</h3>
                                        <p className="text-[10px] font-bold uppercase text-muted-foreground/20">Awaiting match results</p>
                                    </div>
                                </div>
                            </TableCell>
                        </TableRow>
                    )}
                </TableBody>
            </Table>
        </div>
    );
}

"use client";

import { useState } from "react";
import { _Team } from "@/types/index";
import { updateTeam, deleteTeam, assignTeamGroup } from "@/actions/organizer/tournaments/general";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Dialog, DialogContent, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { Pencil, Loader2, Users, Upload, ImageIcon, Trash2, Edit2 } from "lucide-react";
import { useTranslations } from "next-intl";
import { RosterDialog } from "./roster-dialog";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { _cn } from "@/lib/utils";

interface TeamListProps {
    teams: any[];
    tournamentId: string;
    isPro?: boolean;
    showGroupSelector?: boolean;
    organizerId?: string;
}

export function TeamList({ teams, tournamentId, isPro = false, showGroupSelector = false, organizerId }: TeamListProps) {
    const t = useTranslations("Team");

    if (!teams || teams.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center py-12 text-center bg-muted/5 relative overflow-hidden group">
                <div className="absolute top-0 left-0 w-1 h-full bg-muted group-hover:bg-secondary/40 transition-colors" />
                <div className="p-6 bg-background border border-border/10 rotate-12 transition-transform group-hover:rotate-0 shadow-lg mb-4 relative z-10">
                    <Users className="h-8 w-8 text-muted-foreground opacity-30 -rotate-12 group-hover:rotate-0 transition-transform" />
                </div>
                <h3 className="text-xl font-black uppercase italic tracking-tight text-foreground/40 relative z-10">
                    {t("no_teams")}
                </h3>
                <p className="text-[10px] uppercase font-black text-muted-foreground/20 mt-2 flex items-center gap-2 relative z-10">
                    <span className="w-3 h-[1px] bg-muted-foreground/10" />
                    {t("no_teams_desc")}
                    <span className="w-3 h-[1px] bg-muted-foreground/10" />
                </p>
            </div>
        );
    }

    return (
        <div className="flex flex-col divide-y divide-border/10">
            {teams.map((team) => (
                <TeamItem
                    key={team.id}
                    team={team}
                    tournamentId={tournamentId}
                    isPro={isPro}
                    showGroupSelector={showGroupSelector}
                    isReadOnly={team.team?.user_id && team.team.user_id !== organizerId}
                />
            ))}
        </div>
    );
}

function TeamItem({
    team,
    tournamentId,
    isPro,
    showGroupSelector,
    isReadOnly
}: {
    team: any;
    tournamentId: string;
    isPro: boolean;
    showGroupSelector: boolean;
    isReadOnly: boolean;
}) {
    const t = useTranslations("Team");
    const tGroup = useTranslations("Group");
    const tCommon = useTranslations("Common");
    const [open, setOpen] = useState(false);
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
    const [name, setName] = useState(team.name);
    const [logoFile, setLogoFile] = useState<File | null>(null);
    const [previewUrl, setPreviewUrl] = useState<string | null>(null);
    const [existingLogoUrl, _setExistingLogoUrl] = useState(team.logo_url || "");
    const [isLoading, setIsLoading] = useState(false);
    const [isGroupLoading, setIsGroupLoading] = useState(false);
    const [description, setDescription] = useState(team.description || "");


    const handleSave = async () => {
        setIsLoading(true);
        const formData = new FormData();
        formData.append("name", name);
        formData.append("description", description);
        formData.append("existing_logo_url", existingLogoUrl);
        if (logoFile) {
            formData.append("logo", logoFile);
        }

        const result = await updateTeam(team.id, formData, tournamentId);
        setIsLoading(false);
        if (result.success) {
            setOpen(false);
        } else {
            alert(result.error);
        }
    };

    const handleDelete = async () => {
        setIsLoading(true);
        const result = await deleteTeam(team.id, tournamentId);
        setIsLoading(false);
        if (result.success) {
            setOpen(false);
            setShowDeleteConfirm(false);
        } else {
            alert(result.error);
        }
    };

    const handleGroupChange = async (value: string) => {
        setIsGroupLoading(true);
        const groupName = value === "none" ? null : value;
        try {
            const result = await assignTeamGroup(team.id, groupName, tournamentId);
            if (!result.success) {
                alert(`${tCommon("error")}: ${result.error}`);
            }
        } catch (e) {
            console.error(e);
        } finally {
            setIsGroupLoading(false);
        }
    };

    return (
        <div className="flex items-center justify-between px-2 py-4 md:p-6 hover:bg-muted/5 transition-all group relative overflow-hidden">
            {/* Standardized Accent Bar */}
            <div className="absolute left-0 top-0 w-1 h-full bg-secondary opacity-0 group-hover:opacity-100 transition-opacity z-30" />

            <div className="flex items-center flex-1 min-w-0 z-10">
                <div className="h-12 w-12 rounded-none bg-muted/10 flex items-center justify-center mr-2 md:mr-3 shrink-0 overflow-hidden border border-foreground/5 relative">
                    {team.logo_url ? (
                        <img src={team.logo_url} alt={team.name} className="h-full w-full object-contain p-1" />
                    ) : (
                        <span className="text-[10px] font-black text-muted-foreground/40">
                            {team.name.substring(0, 2).toUpperCase()}
                        </span>
                    )}
                </div>
                <div className="flex flex-col min-w-0 mr-2 md:mr-3">
                    <h3 className="font-black uppercase italic tracking-tighter text-lg md:text-xl leading-none truncate group-hover:text-primary transition-colors">{team.name}</h3>
                    {team.description && (
                        <p className="text-[10px] font-bold uppercase text-muted-foreground/40 mt-1.5 line-clamp-1 tracking-wider">{team.description}</p>
                    )}
                    <div className="flex items-center gap-2 mt-1.5 overflow-hidden">
                        {(!showGroupSelector && team.group_name) ? (
                            <Badge variant="outline" className="rounded-none border-secondary/30 text-secondary bg-secondary/5 text-[9px] font-black uppercase italic px-2">
                                {t("group")} {team.group_name}
                            </Badge>
                        ) : (
                            <span className="text-[10px] font-bold uppercase text-muted-foreground/20 italic tracking-tight">{t("participating_team")}</span>
                        )}
                    </div>
                </div>
            </div>

            <div className="flex items-center gap-2 md:gap-3 z-10">
                {showGroupSelector && (
                    <div className="flex items-center gap-2">
                        {isGroupLoading && <Loader2 className="h-3 w-3 animate-spin text-secondary" />}
                        <Select
                            defaultValue={team.group_name || "none"}
                            onValueChange={handleGroupChange}
                            disabled={isGroupLoading}
                        >
                            <SelectTrigger className="w-[110px] h-9 text-[10px] bg-muted/5 border-border/10 rounded-none font-black uppercase tracking-widest focus:ring-secondary/20 transition-all hover:bg-muted/10">
                                <SelectValue placeholder={tGroup("group")} />
                            </SelectTrigger>
                            <SelectContent className="bg-card border-border/10 rounded-none shadow-2xl">
                                <SelectItem value="none" className="text-[10px] font-bold uppercase opacity-40">{tCommon("none") || "None"}</SelectItem>
                                {["A", "B", "C", "D", "E", "F", "G", "H"].map((g) => (
                                    <SelectItem key={g} value={g} className="text-[10px] font-black uppercase">
                                        {tGroup("group")} {g}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>
                )}

                <div className="flex gap-2 shrink-0">
                    {isPro && <RosterDialog teamId={team.id} teamName={team.name} readOnly={isReadOnly} />}

                    {!isReadOnly && (
                        <Dialog open={open} onOpenChange={setOpen}>
                            <DialogTrigger asChild>
                                <Button variant="outline" size="icon" className="h-9 w-9 rounded-none border-border/10 bg-muted/5 hover:bg-foreground/5 hover:border-secondary/30 text-muted-foreground/40 hover:text-secondary transition-all">
                                    <Pencil className="h-4 w-4" />
                                </Button>
                            </DialogTrigger>
                        <DialogContent className="bg-card border-border/10 rounded-none max-w-md shadow-2xl">
                            <DialogHeader>
                                <DialogTitle className="text-xl font-black uppercase italic tracking-tighter text-foreground flex items-center gap-2">
                                    <Edit2 className="h-5 w-5 text-secondary" />
                                    {t("edit_team")}
                                </DialogTitle>
                            </DialogHeader>
                            <div className="space-y-6 py-6 border-y border-border/10 my-4">
                                <div className="space-y-4 justify-center flex">
                                    <div className="flex flex-col items-center gap-3">
                                        <label htmlFor="edit-logo-upload" className="cursor-pointer group relative">
                                            <div className="h-28 w-28 rounded-none border border-border/10 flex items-center justify-center overflow-hidden bg-foreground/5 hover:bg-foreground/10 transition-all group-hover:border-secondary/30 relative">
                                                {previewUrl || existingLogoUrl ? (
                                                    <img
                                                        src={previewUrl || existingLogoUrl}
                                                        alt="Logo Preview"
                                                        className="h-full w-full object-contain p-2"
                                                    />
                                                ) : (
                                                    <ImageIcon className="h-10 w-10 text-muted-foreground/10 group-hover:text-secondary/20 transition-colors" />
                                                )}
                                                <div className="absolute inset-0 bg-secondary/80 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <Upload className="h-6 w-6 text-secondary-foreground" />
                                                </div>
                                            </div>
                                            <Input
                                                id="edit-logo-upload"
                                                type="file"
                                                accept="image/*"
                                                className="hidden"
                                                onChange={(e) => {
                                                    if (e.target.files && e.target.files[0]) {
                                                        const file = e.target.files[0];
                                                        setLogoFile(file);
                                                        setPreviewUrl(URL.createObjectURL(file));
                                                    }
                                                }}
                                            />
                                        </label>
                                        <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground/40 italic">{t("click_to_upload")}</span>
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="name" className="text-[10px] font-black uppercase tracking-wider text-muted-foreground/60">{t("team_name")}</Label>
                                    <Input
                                        id="name"
                                        value={name}
                                        className="bg-foreground/5 border-border/10 rounded-none font-black uppercase italic tracking-tighter h-12 focus-visible:ring-secondary/20"
                                        onChange={(e) => setName(e.target.value)}
                                    />
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="description" className="text-[10px] font-black uppercase tracking-wider text-muted-foreground/60">{t("team_description") || "Team Description"}</Label>
                                    <Textarea
                                        id="description"
                                        value={description}
                                        className="bg-foreground/5 border-border/10 rounded-none font-medium text-sm min-h-[100px] focus-visible:ring-secondary/20"
                                        onChange={(e) => setDescription(e.target.value)}
                                        placeholder={t("no_description") || "No description"}
                                    />
                                </div>
                            </div>
                            <DialogFooter className="flex sm:justify-between w-full gap-4">
                                <Button 
                                    variant="outline" 
                                    onClick={() => setShowDeleteConfirm(true)} 
                                    disabled={isLoading} 
                                    type="button"
                                    className="rounded-none border-destructive/20 bg-destructive/5 text-destructive hover:bg-destructive hover:text-foreground transition-all h-10 px-6 text-[11px] font-black uppercase italic tracking-widest"
                                >
                                    {isLoading ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Trash2 className="h-4 w-4 mr-2" />}
                                    {tCommon("delete")}
                                </Button>
                                <Button 
                                    onClick={handleSave} 
                                    disabled={isLoading}
                                    className="rounded-none bg-secondary text-secondary-foreground hover:bg-secondary/90 transition-all h-10 px-8 text-[11px] font-black uppercase italic tracking-widest"
                                >
                                    {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                                    {tCommon("save")}
                                </Button>
                            </DialogFooter>
                        </DialogContent>
                        </Dialog>
                    )}

                    <AlertDialog open={showDeleteConfirm} onOpenChange={setShowDeleteConfirm}>
                        <AlertDialogContent className="bg-card border-border/10 rounded-none shadow-2xl max-w-md">
                            <AlertDialogHeader>
                                <AlertDialogTitle className="text-xl font-black uppercase italic tracking-tighter text-foreground flex items-center gap-2">
                                    <Trash2 className="h-5 w-5 text-destructive" />
                                    {t("delete_team")}
                                </AlertDialogTitle>
                                <AlertDialogDescription className="text-sm font-medium text-muted-foreground/80 mt-2">
                                    {t("delete_desc")}
                                </AlertDialogDescription>
                            </AlertDialogHeader>
                            <AlertDialogFooter className="mt-6">
                                <AlertDialogCancel className="rounded-none border-border/10 bg-foreground/5 hover:bg-foreground/10 hover:text-foreground transition-all h-10 text-[11px] font-black uppercase tracking-widest">
                                    {tCommon("cancel")}
                                </AlertDialogCancel>
                                <AlertDialogAction
                                    onClick={(e) => {
                                        e.preventDefault();
                                        handleDelete();
                                    }}
                                    disabled={isLoading}
                                    className="rounded-none border border-destructive/20 bg-destructive/90 text-foreground hover:bg-destructive hover:shadow-[0_0_15px_rgba(220,38,38,0.3)] transition-all h-10 text-[11px] font-black uppercase tracking-widest"
                                >
                                    {isLoading ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Trash2 className="h-3.5 w-3.5 mr-2" />}
                                    {t("delete_team")}
                                </AlertDialogAction>
                            </AlertDialogFooter>
                        </AlertDialogContent>
                    </AlertDialog>
                </div>
            </div>
        </div>
    );
}

import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { Goal, Team } from "@/types/index";
import { useTranslations } from "next-intl";
import { Activity } from "lucide-react";
import { cn } from "@/lib/utils";
import { useLocale } from "next-intl";

export function TopScorersTable({ goals, teams }: { goals: Goal[]; teams: Team[] }) {
    const t = useTranslations("TopScorers");
    const _locale = useLocale();

    // Aggregate goals by (team_id, player_name)
    const scorerStats: Record<string, { player_name: string; team_id: string; goals: number }> = {};

    goals.forEach(goal => {
        const key = `${goal.team_id}-${goal.player_name.trim().toLowerCase()}`;
        if (!scorerStats[key]) {
            scorerStats[key] = {
                player_name: goal.player_name,
                team_id: goal.team_id,
                goals: 0
            };
        }
        scorerStats[key].goals += 1;
    });

    const sortedScorers = Object.values(scorerStats).sort((a, b) => b.goals - a.goals);
    const getTeam = (teamId: string) => teams.find(t => t.id === teamId);

    return (
        <div className="w-full">
            <div className="w-full overflow-x-auto rounded-none">
                <Table className="min-w-[400px] border-separate border-spacing-0">
                    <TableHeader className="bg-muted/5">
                        <TableRow className="h-10 border-b border-border/10 hover:bg-muted/5 transition-colors">
                            <TableHead className="w-12 px-0 text-center text-[10px] font-black uppercase tracking-widest text-muted-foreground/60 border-b border-border/10">
                                {t("rank")}
                            </TableHead>
                            <TableHead className="px-4 text-[10px] font-black uppercase tracking-widest text-muted-foreground/60 border-b border-border/10">
                                {t("player")}
                            </TableHead>
                            <TableHead className="px-4 text-[10px] font-black uppercase tracking-widest text-muted-foreground/60 border-b border-border/10">
                                {t("team") || "Team"}
                            </TableHead>
                            <TableHead className="text-center px-4 text-[10px] font-black uppercase tracking-widest text-secondary border-b border-border/10">
                                {t("goals")}
                            </TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {sortedScorers.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={4} className="py-20 bg-muted/2">
                                    <div className="flex flex-col items-center justify-center gap-4 text-center">
                                        <div className="h-16 w-16 rounded-none bg-muted/10 border border-border/10 flex items-center justify-center relative group">
                                            <div className="absolute top-0 left-0 w-1 h-full bg-muted/20" />
                                            <Activity className="h-8 w-8 text-muted-foreground/20 group-hover:text-muted-foreground/40 transition-colors" />
                                        </div>
                                        <div className="space-y-1">
                                            <h3 className="text-sm font-black uppercase italic tracking-widest text-muted-foreground/40">{t("no_goals")}</h3>
                                            <p className="text-[10px] font-bold uppercase text-muted-foreground/20">Awaiting match events</p>
                                        </div>
                                    </div>
                                </TableCell>
                            </TableRow>
                        ) : (
                            sortedScorers.slice(0, 10).map((scorer, index) => {
                                const team = getTeam(scorer.team_id);
                                const isTop3 = index < 3;
                                return (
                                    <TableRow 
                                        key={`${scorer.team_id}-${scorer.player_name}`} 
                                        className="h-12 border-b border-border/5 hover:bg-muted/5 transition-colors group/row"
                                    >
                                        <TableCell className="text-center px-0 border-b border-border/5">
                                            <span className={cn(
                                                "text-[10px] font-black italic tracking-tighter tabular-nums",
                                                isTop3 ? "text-secondary" : "text-muted-foreground/40"
                                            )}>
                                                {String(index + 1).padStart(2, '0')}
                                            </span>
                                        </TableCell>
                                        <TableCell className="px-4 border-b border-border/5">
                                            <span className="text-sm font-black uppercase italic tracking-tighter text-foreground group-hover/row:text-primary transition-colors">
                                                {scorer.player_name}
                                            </span>
                                        </TableCell>
                                        <TableCell className="px-4 border-b border-border/5">
                                            <div className="flex items-center gap-3">
                                                <div className="w-7 h-7 bg-muted/10 border border-border/10 p-1 rounded-none flex items-center justify-center overflow-hidden shrink-0">
                                                    {team?.logo_url ? (
                                                        <img src={team.logo_url} alt="" className="w-full h-full object-contain" />
                                                    ) : (
                                                        <span className="text-[8px] font-black text-muted-foreground/30 capitalize">
                                                            {team?.name.charAt(0)}
                                                        </span>
                                                    )}
                                                </div>
                                                <span className="text-[10px] font-black uppercase italic tracking-tighter text-muted-foreground/60 group-hover/row:text-muted-foreground transition-colors truncate max-w-[120px] md:max-w-none">
                                                    {team?.name}
                                                </span>
                                            </div>
                                        </TableCell>
                                        <TableCell className="text-center px-4 border-b border-border/5">
                                            <span className="text-base font-black text-secondary tabular-nums">
                                                {scorer.goals}
                                            </span>
                                        </TableCell>
                                    </TableRow>
                                );
                            })
                        )}
                    </TableBody>
                </Table>
            </div>
            {sortedScorers.length > 0 && (
                <div className="py-2 flex justify-end">
                    <p className="text-[8px] font-black uppercase italic tracking-widest text-muted-foreground/30">
                        {t("showing_top_10") || "Showing TOP 10 Goal Scorers"}
                    </p>
                </div>
            )}
        </div>
    );
}

"use client";

import { useRef, useEffect, useState, _useCallback } from "react";
import { Match } from "@/types/index";
import { Trophy } from "lucide-react";
import { cn } from "@/lib/utils";
import { useTranslations } from "next-intl";
import { _ExportToImageButton } from "@/components/ui/export-to-image-button";
import { Link } from "@/i18n/routing";

interface TournamentBracketProps {
    matches: Match[];
    isPublic?: boolean;
}

const CONNECTOR_W = 48;
const CARD_W = 232;
const MATCH_SLOT_H = 80; // Base height per match slot in the first round
const MATCH_GAP = 12;    // Gap between cards in a pair

export function TournamentBracket({ matches, isPublic = false }: TournamentBracketProps) {
    const t = useTranslations("Bracket");
    const knockoutMatches = matches.filter(
        (m) => m.stage !== "league" && m.stage !== "group"
    );

    if (knockoutMatches.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center py-12 text-center border border-dashed border-border/20 rounded-none bg-muted/5">
                <div className="h-12 w-12 rounded-none bg-muted/10 flex items-center justify-center mb-4 border border-border/10">
                    <Trophy className="h-6 w-6 text-muted-foreground/40" />
                </div>
                <h3 className="text-xs font-black uppercase tracking-widest text-muted-foreground/60">{t("no_knockout")}</h3>
            </div>
        );
    }

    const allStages = ["round_of_64", "round_of_32", "round_of_16", "quarter_final", "semi_final", "final"];
    const stageLabels: Record<string, string> = {
        round_of_64: t("round_of_64"),
        round_of_32: t("round_of_32"),
        round_of_16: t("round_of_16"),
        quarter_final: t("quarter_final"),
        semi_final: t("semi_final"),
        final: t("final"),
    };

    const matchesByStage = knockoutMatches.reduce((acc, match) => {
        const stage = match.stage;
        if (!acc[stage]) acc[stage] = [];
        acc[stage].push(match);
        return acc;
    }, {} as Record<string, Match[]>);

    const activeStages = allStages.filter(stage => matchesByStage[stage] && matchesByStage[stage].length > 0);

    // Measure actual card height for precise slot sizing
    const [cardHeight, setCardHeight] = useState(MATCH_SLOT_H);
    const measureRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (measureRef.current) {
            const h = measureRef.current.getBoundingClientRect().height;
            if (h > 0) setCardHeight(h);
        }
    }, []);

    // The base slot height = card height + gap
    const baseSlotH = cardHeight + MATCH_GAP;

    return (
        <div className="space-y-4 md:space-y-6">
            {/* Hidden measurement card */}
            <div className="absolute opacity-0 pointer-events-none" style={{ width: CARD_W }}>
                <div ref={measureRef}>
                    <BracketMatchCard match={knockoutMatches[0]} isPublic={isPublic} />
                </div>
            </div>

            <div className="w-full overflow-auto custom-scrollbar scroll-smooth">
                <div id="tournament-bracket-canvas" className="inline-flex items-start">
                    {activeStages.map((stage, stageIndex) => {
                        let stageMatches = matchesByStage[stage];
                        stageMatches = [...stageMatches].sort((a, b) => (a.match_index ?? 0) - (b.match_index ?? 0));

                        const isFinal = stage === 'final';
                        const isLast = stageIndex === activeStages.length - 1;

                        // Each successive round doubles its slot height
                        // stageIndex 0 = first active round = multiplier 1
                        const multiplier = Math.pow(2, stageIndex);
                        const slotHeight = baseSlotH * multiplier;

                        return (
                            <div key={stage} className="flex flex-col shrink-0">
                                {/* Stage label */}
                                <div
                                    className="text-center mb-4 md:mb-6 pr-12"
                                    style={{ width: CARD_W + (!isLast ? CONNECTOR_W : 0) }}
                                >
                                    <span className="text-[10px] font-black uppercase italic tracking-tighter text-secondary/80 bg-secondary/5 px-3 py-1 border-l-2 border-secondary">
                                        {stageLabels[stage] || stage.replace('_', ' ')}
                                    </span>
                                </div>

                                {/* Matches in this stage */}
                                <div className="flex flex-col">
                                    {stageMatches.map((match, idx) => (
                                        <BracketSlot
                                            key={match.id}
                                            match={match}
                                            slotHeight={slotHeight}
                                            isFinal={isFinal}
                                            showConnector={!isLast}
                                            isTopOfPair={idx % 2 === 0}
                                            isBottomOfPair={idx % 2 === 1}
                                            hasPairPartner={!isFinal && stageMatches.length > 1}
                                            isPublic={isPublic}
                                        />
                                    ))}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
}

/**
 * Each match occupies a fixed-height slot. The slot height doubles per round,
 * so matches in round N+1 naturally center between two feeder matches from round N.
 *
 * Connector lines:
 *   - Horizontal stub from card center-right
 *   - Vertical bar from top-of-pair center to bottom-of-pair center (on right edge)
 *   - Output horizontal from vertical bar midpoint to next round
 */
function BracketSlot({
    match,
    slotHeight,
    isFinal,
    showConnector,
    isTopOfPair,
    isBottomOfPair,
    hasPairPartner,
    isPublic,
}: {
    match: Match;
    slotHeight: number;
    isFinal: boolean;
    showConnector: boolean;
    isTopOfPair: boolean;
    isBottomOfPair: boolean;
    hasPairPartner: boolean;
    isPublic?: boolean;
}) {
    return (
        <div
            className="flex items-center relative"
            style={{ height: slotHeight }}
        >
            {/* Match card */}
            <div style={{ width: CARD_W }} className="shrink-0">
                <BracketMatchCard match={match} isFinal={isFinal} isPublic={isPublic} />
            </div>

            {/* Connector lines */}
            {showConnector && (
                <div className="relative shrink-0" style={{ width: CONNECTOR_W, alignSelf: 'stretch' }}>
                    {/* Horizontal stub from card center to vertical bar position */}
                    <div
                        className="absolute bg-secondary/30"
                        style={{
                            left: 0,
                            top: '50%',
                            width: CONNECTOR_W / 2,
                            height: 1,
                            transform: 'translateY(-0.5px)',
                        }}
                    />

                    {hasPairPartner && (
                        <>
                            {/* Vertical bar: top-of-pair extends downward, bottom-of-pair extends upward */}
                            {isTopOfPair && (
                                <div
                                    className="absolute bg-secondary/30"
                                    style={{
                                        left: CONNECTOR_W / 2 - 0.5,
                                        top: '50%',
                                        width: 1,
                                        bottom: 0,
                                    }}
                                />
                            )}
                            {isBottomOfPair && (
                                <>
                                    <div
                                        className="absolute bg-secondary/30"
                                        style={{
                                            left: CONNECTOR_W / 2 - 0.5,
                                            top: 0,
                                            width: 1,
                                            height: '50%',
                                        }}
                                    />
                                    {/* Output horizontal from vertical bar to next round */}
                                    <div
                                        className="absolute bg-secondary/30"
                                        style={{
                                            left: CONNECTOR_W / 2,
                                            top: 0,
                                            width: CONNECTOR_W / 2,
                                            height: 1,
                                        }}
                                    />
                                </>
                            )}
                        </>
                    )}

                    {/* Single match (no pair): straight horizontal through */}
                    {!hasPairPartner && (
                        <div
                            className="absolute bg-secondary/30"
                            style={{
                                left: CONNECTOR_W / 2,
                                top: '50%',
                                width: CONNECTOR_W / 2,
                                height: 1,
                                transform: 'translateY(-0.5px)',
                            }}
                        />
                    )}
                </div>
            )}
        </div>
    );
}

function BracketMatchCard({ match, isFinal, isPublic }: { match: Match; isFinal?: boolean; isPublic?: boolean }) {
    const t = useTranslations("Bracket");
    const tournamentId = match.tournament_id;
    const isFinished = match.status === "finished";
    const isScheduled = match.status === "scheduled";
    const homeWinner = match.winner_id && match.winner_id === match.home_team_id;
    const awayWinner = match.winner_id && match.winner_id === match.away_team_id;
    const hasPenalties = !isScheduled && ((match.penalty_home_score ?? 0) > 0 || (match.penalty_away_score ?? 0) > 0);

    const url = isPublic 
        ? `/${tournamentId}/matches/${match.id}`
        : `/organizer/tournaments/${tournamentId}/matches/${match.id}`;

    return (
        <Link 
            href={url}
            className={cn(
                "flex flex-col border border-border/40 bg-card rounded-none overflow-hidden text-sm relative transition-all group",
                "shadow-lg hover:border-secondary/30",
                isFinal && "border-secondary/40 shadow-[0_0_20px_rgba(0,196,154,0.1)]",
                !isFinished && "opacity-95"
            )}
        >
             {/* Dynamic color strip on top */}
             <div className={cn(
                "h-0.5 w-full",
                isFinal ? "bg-secondary shadow-[0_0_8px_rgba(0,196,154,0.6)]" : "bg-muted/20 group-hover:bg-secondary/40"
            )} />

            {/* Header */}
            <div className="flex justify-between items-center px-3 py-1.5 bg-muted/10 border-b border-border/20">
                <span className="text-[8px] font-black uppercase italic tracking-widest text-muted-foreground/50 flex items-center gap-1.5">
                    {isFinal && <Trophy className="h-2.5 w-2.5 text-secondary" />}
                    {t("match")} {(match.match_index !== undefined && match.match_index !== null) ? `#${match.match_index}` : ""}
                </span>
                <div className="flex items-center gap-1">
                    {match.status === 'live' && (
                        <div className="flex items-center gap-1 bg-red-500/10 px-1.5 py-0.5 rounded-none">
                            <span className="h-1 w-1 bg-red-500 rounded-full animate-pulse" />
                            <span className="text-[8px] font-black uppercase italic text-red-500 tracking-tighter">
                                {t("live")}
                            </span>
                        </div>
                    )}
                    {isFinished && (
                        <span className="text-[8px] font-black uppercase italic text-muted-foreground/40 tracking-tighter">
                            {t("ft")}
                        </span>
                    )}
                </div>
            </div>

            {/* Home Team */}
            <TeamRow
                name={match.home_team?.name}
                logoUrl={match.home_team?.logo_url}
                score={isScheduled ? null : match.home_score}
                penaltyScore={hasPenalties ? match.penalty_home_score : undefined}
                isWinner={!!homeWinner}
                tbd={t("tbd")}
            />

            {/* Away Team */}
            <TeamRow
                name={match.away_team?.name}
                logoUrl={match.away_team?.logo_url}
                score={isScheduled ? null : match.away_score}
                penaltyScore={hasPenalties ? match.penalty_away_score : undefined}
                isWinner={!!awayWinner}
                tbd={t("tbd")}
            />
        </Link>
    );
}

function TeamRow({
    name,
    logoUrl,
    score,
    penaltyScore,
    isWinner,
    tbd,
}: {
    name?: string;
    logoUrl?: string | null;
    score: number | null | undefined;
    penaltyScore?: number | null;
    isWinner: boolean;
    tbd: string;
}) {
    return (
        <div className={cn(
            "flex justify-between items-center px-3 py-2 gap-2 transition-colors relative",
            isWinner ? "bg-secondary/[0.03]" : ""
        )}>
            {isWinner && (
                <div className="absolute left-0 top-1/2 -translate-y-1/2 w-0.5 h-4/5 bg-secondary shadow-[0_0_8px_rgba(0,196,154,0.4)]" />
            )}
            <div className="flex items-center gap-2.5 overflow-hidden flex-1 min-w-0">
                <div className="w-5 h-5 bg-muted/10 border border-border/10 p-0.5 rounded-none shrink-0 flex items-center justify-center overflow-hidden">
                    {logoUrl ? (
                        <img src={logoUrl} className="w-full h-full object-contain" alt="" />
                    ) : (
                        <span className="text-[9px] font-black text-muted-foreground/30 capitalize">
                            {name?.charAt(0) || "?"}
                        </span>
                    )}
                </div>
                <span className={cn(
                    "truncate text-[11px] font-black uppercase italic tracking-tighter transition-colors",
                    isWinner ? "text-foreground" : "text-muted-foreground/60"
                )}>
                    {name || tbd}
                </span>
            </div>
            <div className="flex items-center gap-1 shrink-0">
                {penaltyScore != null && (
                    <span className="text-[9px] font-black text-muted-foreground/30 italic">
                        ({penaltyScore})
                    </span>
                )}
                <span className={cn(
                    "text-xs min-w-[16px] text-center font-black italic tracking-tighter",
                    isWinner ? "text-secondary" : "text-muted-foreground/60"
                )}>
                    {score ?? "-"}
                </span>
            </div>
        </div>
    );
}

